package com.harmony.uspace.domain;

import com.harmony.bitable.BitfieldType;
import com.harmony.bitable.annotations.BitId;
import com.harmony.bitable.annotations.Bitable;
import com.harmony.bitable.annotations.Bitfield;
import lombok.Getter;
import lombok.Setter;
import lombok.experimental.Accessors;

import java.util.List;

/**
 * @author wuxin
 */
@Getter
@Setter
@Bitable("邮箱配置")
@Accessors(chain = true)
public class Mailbox implements Recordable {

    @BitId
    private String recordId;

    @Bitfield("邮箱账号")
    private String account;

    @Bitfield("授权码")
    private String password;

    @Bitfield(name = "自动监听", type = BitfieldType.CHECKBOX)
    private Boolean autoWatch;

    @Bitfield(name = "邮箱厂商", type = BitfieldType.SINGLE_SELECT)
    private String vendor;

    @Bitfield(name = "所有文件夹", type = BitfieldType.MULTI_SELECT)
    private List<String> allFolders;

    @Bitfield(name = "可读文件夹", type = BitfieldType.MULTI_SELECT, readonly = true)
    private List<String> readableFolders;

}

