package com.harmony.uspace.domain;

import com.harmony.bitable.annotations.Bitable;
import com.harmony.bitable.annotations.Bitfield;
import lombok.Getter;
import lombok.Setter;
import lombok.experimental.Accessors;

import java.util.Objects;

/**
 * @author wuxin
 */
@Getter
@Setter
@Accessors(chain = true)
@Bitable("交易对方")
public class Counterparty extends BaseDomain {

    @Bitfield("对方名称")
    private String name;

    @Bitfield("对方账号")
    private String account;

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Counterparty that = (Counterparty) o;
        return Objects.equals(name, that.name) && Objects.equals(account, that.account);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, account);
    }

}

