package com.harmony.uspace.service.mail;

import com.harmony.uspace.support.MailMessageHandler;
import com.harmony.uspace.support.mail.MailMessage;
import org.apache.commons.lang3.StringUtils;

/**
 * @author wuxin
 */
abstract class AbstractBillMessageHandler implements MailMessageHandler {

    protected boolean isMessageFromDomain(MailMessage message, String domain) {
        return message.getFrom()
                .stream()
                .anyMatch(from -> StringUtils.endsWithIgnoreCase(from.getAddress(), domain));
    }

}

