package com.harmony.uspace.listener;

import com.harmony.uspace.domain.BillDocument;
import com.harmony.uspace.listener.event.BillFileDownloadCompletedEvent;
import com.harmony.uspace.service.BillDocumentService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Component;

/**
 * @author wuxin
 */
@Slf4j
@RequiredArgsConstructor
@Component
public class BillFileEventListener {

    private final BillDocumentService billDocumentService;

    @Async
    @EventListener
    public void onBillFileDownloadCompleted(BillFileDownloadCompletedEvent event) {
        log.info("Received BillFileDownloadCompletedEvent, file: {}", event.getSource());
        try {
            // 阶段1: 创建记录（仅上传文件）
            BillDocument billDocument = billDocumentService.createBillDocument(event.getSource());
            log.info("Created bill document record: {}", billDocument.getRecordId());

            // 阶段2: 异步解析文件（解码、提取、同步）
            billDocumentService.resolveBillDocument(billDocument.getRecordId());
            log.info("Resolved bill document: {}", billDocument.getRecordId());
        } catch (Exception e) {
            log.error("Failed to process bill file: {}", event.getSource(), e);
            throw new RuntimeException(e);
        }
    }

}

