package com.harmony.uspace.scheduler;

import com.harmony.uspace.dao.MailboxDao;
import com.harmony.uspace.domain.Mailbox;
import com.harmony.uspace.service.MailboxService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.util.List;

/**
 * 邮箱定时轮询调度器
 * 定时轮询所有开启自动监听的邮箱
 *
 * @author wuxin
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class MailboxPollingScheduler {

    private final MailboxDao mailboxDao;
    private final MailboxService mailboxService;

    /**
     * 定时轮询任务
     * 初始延迟和轮询间隔通过配置文件指定
     */
    @Scheduled(initialDelayString = "${mailbox.polling.initial-delay:1m}", fixedRateString = "${mailbox.polling.interval:30m}")
    public void pollMailboxes() {
        log.debug("Start polling mailboxes for new messages");

        List<Mailbox> watchableMailboxes = mailboxDao.getAllWatchableMailbox();

        if (watchableMailboxes.isEmpty()) {
            log.debug("No watchable mailboxes found");
            return;
        }

        log.info("Polling {} mailboxes for new messages", watchableMailboxes.size());

        for (Mailbox mailbox : watchableMailboxes) {
            try {
                mailboxService.readAndDispatchBillMessages(mailbox);
            } catch (Exception e) {
                log.error("Failed to poll mailbox: {}", mailbox.getAccount(), e);
            }
        }

        log.debug("Completed polling mailboxes");
    }
}

