package com.harmony.uspace.service;

import com.harmony.uspace.domain.BillDocument;
import com.harmony.uspace.domain.BillRow;
import com.harmony.uspace.domain.Counterparty;
import com.harmony.uspace.dto.bill.BillDetails;
import com.harmony.uspace.options.ResolveStatus;
import com.harmony.uspace.repository.BillDocumentRepository;
import com.harmony.uspace.service.bill.BillFileResolvers;
import com.harmony.uspace.support.LarkFacade;
import com.harmony.uspace.support.ZipPasswordCracker;
import com.harmony.uspace.utils.LarkUtils;
import com.harmony.uspace.utils.ZipUtils;
import com.lark.oapi.service.bitable.v1.model.Attachment;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.data.util.Lazy;
import org.springframework.stereotype.Service;
import org.springframework.util.CollectionUtils;

import java.io.File;
import java.io.IOException;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

/**
 * @author wuxin
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class BillDocumentService {

    private final BillDocumentRepository billDocumentRepository;

    private final BillRowService billRowService;
    private final CounterpartyService counterpartyService;

    private final LarkFacade larkFacade;
    private final BillFileResolvers billFileResolver;
    private final ZipPasswordCracker passwordCracker;

    /**
     * 创建 billDocument 基础信息 - 仅上传加密文件到飞书
     * 文件解码和解析由 resolveBillDocument 异步处理
     *
     * @param encryptedZipFile 加密后的账单文件
     */
    public BillDocument createBillDocument(File encryptedZipFile) throws Exception {
        // 上传加密附件到飞书云盘
        String attachmentToken = larkFacade.uploadBitableResource(encryptedZipFile);

        // 创建记录，所有解析状态均为未完成
        BillDocument billDocument = new BillDocument()
                .setAttachmentResolved(false)
                .setBaseResolved(false)
                .setRowResolveStatus(ResolveStatus.PENDING)
                .setCounterpartyResolveStatus(ResolveStatus.PENDING)
                .setAttachments(LarkUtils.fromTokens(attachmentToken));

        return billDocumentRepository.save(billDocument);
    }

    public BillDocument resolveBillDocument(String recordId) throws Exception {
        BillDocument billDocument = billDocumentRepository.findById(recordId).orElseThrow();

        BillDocumentResolveContext context = new BillDocumentResolveContext(billDocument);

        // 依次执行各阶段，每个阶段内部负责处理状态和更新
        resolvePassword(context);
        resolveBillAttachments(context);
        resolveBillDetails(context);
        resolveBillRows(context);

        log.info("Bill document {} fully resolved", recordId);
        return billDocument;
    }

    private void resolveBillAttachments(BillDocumentResolveContext context) throws Exception {
        if (context.isAttachmentResolved()) {
            log.debug("Attachment already resolved for bill document {}", context.billDocument.getRecordId());
            return;
        }

        File attachmentFile = context.getFirstAttachment();
        if (attachmentFile == null) {
            log.warn("bill attachments is empty");
            context.billDocument.setAttachmentResolved(true);
            return;
        }

        String password = context.billDocument.getPassword();
        if (StringUtils.isBlank(password)) {
            throw new IllegalStateException("Password not resolved, call resolvePassword first");
        }

        File documentFile = unzipAttachment(attachmentFile, password);
        String documentToken = larkFacade.uploadBitableResource(documentFile);

        context.setFirstDocument(documentToken, documentFile);
        context.billDocument.setAttachmentResolved(true);

        // 解压完成后立即更新到飞书
        billDocumentRepository.update(context.billDocument);
        log.info("Bill document {} - 附件解压完成 (已保存到飞书)", context.billDocument.getRecordId());
    }

    /**
     * 破解加密附件的密码并保存到 billDocument
     */
    private void resolvePassword(BillDocumentResolveContext context) throws Exception {
        // 如果已有密码，跳过
        if (StringUtils.isNotBlank(context.billDocument.getPassword())) {
            log.debug("Password already exists for bill document {}", context.billDocument.getRecordId());
            return;
        }

        File attachmentFile = context.getFirstAttachment();
        if (attachmentFile == null) {
            log.warn("bill attachments is empty, cannot resolve password");
            return;
        }

        String password = passwordCracker.obtainPassword(attachmentFile);
        context.billDocument.setPassword(password);

        // 破解完成后立即更新到飞书
        billDocumentRepository.update(context.billDocument);
        log.info("Bill document {} - 密码破解完成 (已保存到飞书)", context.billDocument.getRecordId());
    }

    private void resolveBillDetails(BillDocumentResolveContext context) {
        if (context.isDocumentResolved()) {
            log.debug("Bill details already resolved for bill document {}", context.billDocument.getRecordId());
            return;
        }

        BillDetails billDetails = context.getBillDetails();
        context.billDocument
                .setBaseResolved(true)
                .setSha256(billDetails.getSha256())
                .setAccountType(billDetails.getAccountType())
                .setAccountNo(billDetails.getAccountNo())
                .setAccountName(billDetails.getAccountName())
                .setStartTime(billDetails.getStartTime())
                .setEndTime(billDetails.getEndTime())
                .setRevenueAmount(billDetails.getRevenueAmount())
                .setRevenueCount(billDetails.getRevenueCount())
                .setExpenseAmount(billDetails.getExpenseAmount())
                .setExpenseCount(billDetails.getExpenseCount());

        // 解析完成后立即更新到飞书
        billDocumentRepository.update(context.billDocument);
        log.info("Bill document {} - 元数据解析完成 (已保存到飞书)", context.billDocument.getRecordId());
    }

    private void resolveBillRows(BillDocumentResolveContext context) {
        String recordId = context.billDocument.getRecordId();

        ResolveStatus counterpartyResolveStatus = context.billDocument.getCounterpartyResolveStatus();
        if (ResolveStatus.isProcessable(counterpartyResolveStatus)) {
            Set<Counterparty> counterpartySet = context.getBillDetails()
                    .getBillRows()
                    .stream()
                    .map(this::extractCounterparty)
                    .collect(Collectors.toSet());
            counterpartyService.handleCounterpartiesAsync(recordId, counterpartySet);
        }

        ResolveStatus rowResolveStatus = context.billDocument.getRowResolveStatus();
        if (ResolveStatus.isProcessable(rowResolveStatus)) {
            billRowService.handleBillRowsAsync(recordId, context.getBillDetails().getBillRows());
        }
    }

    private Counterparty extractCounterparty(BillRow billRow) {
        return new Counterparty()
                .setName(billRow.getCounterpartyName())
                .setAccount(billRow.getCounterpartyAccount());
    }

    private File downloadFirstBillFile(List<Attachment> attachments) {
        if (CollectionUtils.isEmpty(attachments)) {
            throw new IllegalArgumentException("账单文件为空");
        }
        try {
            return larkFacade.downloadAttachment(attachments.getFirst());
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    /**
     * 解压加密附件，提取账单文档
     *
     * @param encryptedZipFile 加密的 ZIP 文件
     * @param password 解压密码
     * @return 解压后的账单文档文件
     * @throws IOException 解压失败
     * @throws IllegalArgumentException ZIP 中不包含支持的账单文档格式
     */
    private File unzipAttachment(File encryptedZipFile, String password) throws IOException {
        File documentFile = ZipUtils.unzipFirst(encryptedZipFile, password, f -> {
            String filename = f.getFilename().toLowerCase();
            return filename.endsWith(".csv") || filename.endsWith(".xlsx");
        });
        if (documentFile == null) {
            throw new IllegalArgumentException("Encrypted zip file does not contain a supported bill document (.csv or .xlsx)");
        }
        return documentFile;
    }

    private class BillDocumentResolveContext {

        private final BillDocument billDocument;
        private final Lazy<File> firstAttachment;

        private Lazy<File> firstDocument;
        private Lazy<BillDetails> billDetails;

        public BillDocumentResolveContext(BillDocument billDocument) {
            this.billDocument = billDocument;
            this.firstAttachment = Lazy.of(() -> downloadFirstBillFile(billDocument.getAttachments()));
            this.firstDocument = Lazy.of(() -> downloadFirstBillFile(billDocument.getDocuments()));
            this.billDetails = Lazy.of(() -> billFileResolver.resolveBillFile(firstDocument.get()));
        }

        public boolean isAttachmentResolved() {
            return Boolean.TRUE.equals(billDocument.getAttachmentResolved());
        }

        public boolean isDocumentResolved() {
            return Boolean.TRUE.equals(billDocument.getBaseResolved());
        }

        public File getFirstAttachment() {
            return firstAttachment.getNullable();
        }

        public File getFirstDocument() {
            return firstDocument.getNullable();
        }

        public BillDetails getBillDetails() {
            return billDetails.getNullable();
        }

        public void setFirstDocument(String fileToken, File file) {
            this.firstDocument = Lazy.of(file);
            this.billDocument.setDocuments(LarkUtils.fromTokens(fileToken));
        }

    }

}

