package com.harmony.uspace.support;

import com.harmony.uspace.support.mail.ReadableMailMessage;
import jakarta.mail.Flags;
import jakarta.mail.Message;
import jakarta.mail.MessagingException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.ObjectProvider;
import org.springframework.stereotype.Component;

import java.io.IOException;

/**
 * 邮件消息分发器
 * 负责将邮件分发给对应的处理器
 *
 * @author wuxin
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class MailMessageDispatcher {

    private final ObjectProvider<MailMessageHandler> mailMessageHandlers;

    /**
     * 分发邮件消息
     *
     * @param message 邮件消息
     * @throws MessagingException 如果分发失败
     * @throws IOException 如果读取消息内容失败
     */
    public void dispatch(Message message) throws MessagingException, IOException {
        ReadableMailMessage mailMessage = new ReadableMailMessage(message);
        log.debug("Dispatch mail message: {}", mailMessage);
        for (MailMessageHandler handler : mailMessageHandlers) {
            if (handler.canHandle(mailMessage)) {
                log.info("Handle message by {}. Message is {}", handler, message);
                handler.handle(mailMessage);
            }
        }
    }

    /**
     * 分发邮件消息并标记为已读
     *
     * @param message 邮件消息
     * @throws MessagingException 如果分发或标记失败
     * @throws IOException 如果读取消息内容失败
     */
    public void dispatchAndMarkAsRead(Message message) throws MessagingException, IOException {
        try {
            dispatch(message);

            // 分发成功后标记已读
            if (!message.isSet(Flags.Flag.SEEN)) {
                message.setFlag(Flags.Flag.SEEN, true);
                log.debug("Marked message as read: {}", message.getSubject());
            }
        } catch (Exception e) {
            log.error("Failed to dispatch and mark message as read", e);
            throw e;
        }
    }

}

