package com.harmony.uspace.service.bill;

import com.harmony.uspace.dto.bill.BillDetails;
import com.harmony.uspace.dto.bill.LineValues;
import com.harmony.uspace.service.bill.reader.BillFileReader;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.ObjectProvider;
import org.springframework.stereotype.Service;

import java.io.File;
import java.io.IOException;

/**
 * @author wuxin
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class BillFileResolvers {

    private final ObjectProvider<BillContentResolver> billFileResolvers;
    private final ObjectProvider<BillFileReader> billFileReaders;

    public BillDetails resolveBillFile(File file) {
        try {
            LineValues contents = readLineValues(file);
            return filterBillFileResolver(contents).resolve(contents);
        } catch (IOException e) {
            throw new IllegalStateException(e);
        }
    }

    private BillContentResolver filterBillFileResolver(LineValues lineValues) {
        return billFileResolvers.stream()
                .filter(e -> e.canResolve(lineValues))
                .findFirst()
                .orElseThrow();
    }

    private LineValues readLineValues(File file) throws IOException {
        return billFileReaders.stream()
                .filter(reader -> reader.supports(file.getName()))
                .findFirst()
                .orElseThrow(() -> new IllegalArgumentException("Unsupported file format: " + file.getName()))
                .read(file);
    }

    /**
     * @author wuxin
     */
    interface BillContentResolver {

        boolean canResolve(LineValues lineValues);

        BillDetails resolve(LineValues lineValues);

    }

}

