package com.harmony.uspace.service.mail;

import com.harmony.uspace.listener.event.BillFileDownloadCompletedEvent;
import com.harmony.uspace.support.MailMessageHandler;
import com.harmony.uspace.support.mail.MailMessage;
import com.harmony.uspace.utils.FileUtils;
import com.harmony.uspace.utils.MessageUtils;
import jakarta.mail.BodyPart;
import jakarta.mail.Message;
import jakarta.mail.MessagingException;
import jakarta.mail.internet.MimeUtility;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.context.ApplicationEventPublisher;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Component;
import org.springframework.util.StreamUtils;

import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.nio.file.Files;
import java.util.concurrent.atomic.AtomicReference;

/**
 * @author wuxin
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class AlipayBillMessageHandler implements MailMessageHandler {

    private final MediaType contentTypeOfAttachment = MediaType.APPLICATION_OCTET_STREAM;
    private final ApplicationEventPublisher applicationEventPublisher;

    @Override
    public boolean canHandle(MailMessage message) {
        return StringUtils.contains(message.getSubject(), "交易流水明细");
    }

    @Override
    public void handle(MailMessage message) throws MessagingException, IOException {
        Message rawMessage = message.getRawMessage();
        File billAttachment = readBillAttachmentFromMessage(rawMessage);
        if (billAttachment == null) {
            throw new MessagingException("message not contains any attachments");
        }
        applicationEventPublisher.publishEvent(new BillFileDownloadCompletedEvent(billAttachment));
    }

    private File readBillAttachmentFromMessage(Message message) throws MessagingException, IOException {
        AtomicReference<BodyPart> attachmentPartRef = new AtomicReference<>();
        MessageUtils.readMessageContentParts(message, part -> {
            MediaType contentType = MediaType.parseMediaType(part.getContentType());
            if (contentTypeOfAttachment.equalsTypeAndSubtype(contentType)
                    && part instanceof BodyPart bodyPart) {
                attachmentPartRef.set(bodyPart);
                return MessageUtils.PartReading.BREAK;
            }
            return MessageUtils.PartReading.NEXT;
        });
        if (attachmentPartRef.get() == null) {
            return null;
        }
        return readBillAttachmentFromPart(attachmentPartRef.get());
    }

    private File readBillAttachmentFromPart(BodyPart bodyPart) throws MessagingException, IOException {
        String filename = MimeUtility.decodeText(bodyPart.getFileName());
        File attachmentFile = FileUtils.createTempFile(filename);
        try (InputStream is = bodyPart.getInputStream();
             OutputStream os = Files.newOutputStream(attachmentFile.toPath())) {
            StreamUtils.copy(is, os);
            log.info("Download alipay bill file {}", attachmentFile);
        }
        return attachmentFile;
    }

}

