package com.harmony.uspace.options;

import com.harmony.bitable.core.Option;
import org.jetbrains.annotations.NotNull;

/**
 * @author wuxin
 */
public enum ResolveStatus implements Option {

    PENDING("待解析"),
    PROCESSING("解析中"),
    SUCCESS("解析成功"),
    FAILURE("解释失败");

    public final String value;

    ResolveStatus(String value) {
        this.value = value;
    }

    @NotNull
    @Override
    public String getValue() {
        return value;
    }

    public static boolean isProcessable(ResolveStatus resolveStatus) {
        return resolveStatus == null || resolveStatus == PENDING || resolveStatus == FAILURE;
    }

}

