package com.harmony.uspace.service;

import com.harmony.uspace.domain.Mailbox;
import com.harmony.uspace.support.mail.MailReader;
import com.harmony.uspace.support.mail.MailReaderProvider;
import jakarta.mail.Folder;
import jakarta.mail.Message;
import jakarta.mail.MessagingException;
import jakarta.mail.search.SearchTerm;
import jakarta.mail.search.FlagTerm;
import jakarta.mail.search.AndTerm;
import jakarta.mail.Flags;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.ObjectUtils;
import org.jetbrains.annotations.NotNull;
import org.springframework.stereotype.Service;
import org.springframework.util.function.ThrowingConsumer;

import java.util.List;

/**
 * @author wuxin
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class MailReadService {

    private final MailReaderProvider mailReaderProvider;

    /**
     * 获取邮箱文件夹
     */
    public List<String> getMailboxFolders(Mailbox mailbox) {
        try (MailReader reader = mailReaderProvider.createMailReader(mailbox)) {
            return reader.listFolders();
        } catch (MessagingException e) {
            throw new IllegalStateException("Unable read mailbox", e);
        }
    }

    /**
     * 读取邮件
     *
     * @param mailbox 邮箱配置
     * @param messageHandler 邮件处理器
     * @param term 搜索条件
     */
    public void readMessages(Mailbox mailbox, @NotNull ThrowingConsumer<Message> messageHandler, SearchTerm term) {
        List<String> readableFolders = mailbox.getReadableFolders();
        if (ObjectUtils.isEmpty(readableFolders)) {
            log.warn("Mailbox {} no readable folders.", mailbox.getAccount());
            return;
        }
        try (MailReader reader = mailReaderProvider.createMailReader(mailbox)) {
            for (String folder : readableFolders) {
                reader.readMessages(folder, messageHandler, term, Folder.READ_ONLY);
            }
        } catch (MessagingException e) {
            throw new IllegalStateException(e);
        }
    }

    /**
     * 读取未读邮件
     *
     * @param mailbox 邮箱配置
     * @param messageHandler 邮件处理器
     * @param term 额外的搜索条件（如发件人）
     */
    public void readUnreadMessages(Mailbox mailbox, @NotNull ThrowingConsumer<Message> messageHandler, SearchTerm term) {
        List<String> readableFolders = mailbox.getReadableFolders();
        if (ObjectUtils.isEmpty(readableFolders)) {
            log.warn("Mailbox {} no readable folders.", mailbox.getAccount());
            return;
        }

        try (MailReader reader = mailReaderProvider.createMailReader(mailbox)) {
            // 组合未读标记和其他搜索条件
            SearchTerm unseenTerm = new FlagTerm(new Flags(Flags.Flag.SEEN), false);
            SearchTerm combinedTerm = term != null ? new AndTerm(unseenTerm, term) : unseenTerm;

            for (String folder : readableFolders) {
                reader.readMessages(folder, messageHandler, combinedTerm, Folder.READ_WRITE);
            }
        } catch (MessagingException e) {
            throw new IllegalStateException("Failed to read unread messages from mailbox: " + mailbox.getAccount(), e);
        }
    }

}

