package com.harmony.uspace.support;

import com.harmony.uspace.utils.ZipUtils;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.IntegerRange;
import org.apache.commons.lang3.StringUtils;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.stereotype.Component;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorCompletionService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * @author wuxin
 */
@Slf4j
@Component
public class ZipPasswordCracker {

    public static final String PASSWORD_CRACKER_EXECUTOR = "PasswordCrackerExecutor";

    private final ExecutorService executorService;
    private final IntegerRange range = IntegerRange.of(0, 999999);
    private final int taskSize = 10;

    public ZipPasswordCracker(@Qualifier(PASSWORD_CRACKER_EXECUTOR) ExecutorService executorService) {
        this.executorService = executorService;
    }

    public String obtainPassword(File zipFile) {
        List<IntegerRange> splitRange = splitRange();
        int totalPasswords = range.getMaximum() - range.getMinimum();

        log.info("Starting password cracking: total {} passwords to try, split into {} tasks",
                totalPasswords, splitRange.size());

        AtomicBoolean found = new AtomicBoolean(false);
        ExecutorCompletionService<String> completionService = new ExecutorCompletionService<>(executorService);

        for (IntegerRange subRange : splitRange) {
            completionService.submit(() -> ZipUtils.obtainPassword(zipFile, subRange, found::get));
        }

        for (int i = 0; i < splitRange.size(); i++) {
            try {
                Future<String> completedTask = completionService.take();
                String password = completedTask.get();
                if (StringUtils.isNotBlank(password)) {
                    found.set(true);
                    log.info("Password found: {}", password);
                    return password;
                }
            } catch (InterruptedException | ExecutionException e) {
                log.warn("Handle completed task error", e);
            }
        }

        log.warn("Password not found after trying all passwords");
        return null;
    }

    private List<IntegerRange> splitRange() {
        int min = range.getMinimum();
        int max = range.getMaximum();
        int total = max - min + 1;
        int chunk = total / taskSize;

        List<IntegerRange> result = new ArrayList<>(taskSize);
        for (int current = 0; current < max; ) {
            int nextMax = Math.min(current + chunk, max);
            result.add(IntegerRange.of(current, nextMax));
            current = nextMax + 1;
        }
        return result;
    }

}

