package com.harmony.uspace.controller.bitable;

import com.harmony.uspace.domain.Mailbox;
import com.harmony.uspace.dto.IdObject;
import com.harmony.uspace.service.MailboxService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.Map;

/**
 * @author wuxin
 */
@RestController
@RequiredArgsConstructor
@RequestMapping("/bitable/mailbox")
public class MailboxEventController {

    private final MailboxService mailboxService;

    @PostMapping("/on-created/{recordId}")
    public ResponseEntity<IdObject> onRegister(@PathVariable String recordId) {
        Mailbox mailbox = mailboxService.handleMailboxRegistered(recordId);
        return ResponseEntity.ok(mailbox.toIdObject());
    }

    @PostMapping("/on-auto-watch-changed/{recordId}")
    public ResponseEntity<Map<String, Object>> onAutoWatchChanged(@PathVariable String recordId,
                                                                  @RequestParam(value = "autoWatch", defaultValue = "false") Boolean autoWatch) {
        // 轮询模式下，定时任务会自动查询所有 autoWatch=true 的邮箱，无需手动启动/停止监听
        return ResponseEntity.ok(Map.of());
    }

}

