```java
@Component
public class HealthAnalysisEngine {

    public HealthStatus determineStatus(HealthMetricsData metrics) {
        int score = 0;

        // 储蓄率评分 (最高40分)
        if (metrics.getSavingRate() >= 30) score += 40;
        else if (metrics.getSavingRate() >= 10) score += 20;

        // 收支比评分 (最高30分)
        if (metrics.getIncomeExpenseRatio() <= 0.7) score += 30;
        else if (metrics.getIncomeExpenseRatio() <= 0.9) score += 15;

        // 波动性评分 (最高30分)
        if (metrics.getVolatilityRate() <= 0.3) score += 30;
        else if (metrics.getVolatilityRate() <= 0.5) score += 15;

        // 综合判定
        if (score >= 80) return HealthStatus.EXCELLENT;
        if (score >= 60) return HealthStatus.GOOD;
        if (score >= 40) return HealthStatus.WARNING;
        return HealthStatus.DANGER;
    }

    public List<HealthAlert> generateAlerts(HealthMetricsData metrics) {
        List<HealthAlert> alerts = new ArrayList<>();

        if (metrics.getSavingRate() < 10) {
            alerts.add(HealthAlert.danger(
                "储蓄率过低",
                "当前储蓄率仅%.1f%%，建议提高到20%%以上",
