package com.harmony.uspace.dto.statistics;

import lombok.Getter;

/**
 * 财务健康状态
 */
@Getter
public enum HealthStatus {
    EXCELLENT("excellent", "🟢", "优秀", 80),
    GOOD("good", "🟡", "良好", 60),
    WARNING("warning", "🟠", "预警", 40),
    DANGER("danger", "🔴", "危险", 0);

    private final String code;
    private final String icon;
    private final String label;
    private final int scoreThreshold;

    HealthStatus(String code, String icon, String label, int scoreThreshold) {
        this.code = code;
        this.icon = icon;
        this.label = label;
        this.scoreThreshold = scoreThreshold;
    }

    /**
     * 根据评分获取健康状态
     */
    public static HealthStatus fromScore(int score) {
        if (score >= EXCELLENT.scoreThreshold) return EXCELLENT;
        if (score >= GOOD.scoreThreshold) return GOOD;
        if (score >= WARNING.scoreThreshold) return WARNING;
        return DANGER;
    }
}
