### 6.2 HealthAnalysisEngine.java

```java
package com.harmony.uspace.service.statistics;

import com.harmony.uspace.dto.statistics.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Component;

import java.util.ArrayList;
import java.util.List;

/**
 * 财务健康分析引擎
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class HealthAnalysisEngine {

    /**
     * 计算健康得分和状态
     *
     * @param metrics 健康度指标数据
     */
    public void analyze(HealthMetricsData metrics) {
        int score = calculateScore(metrics);
        metrics.setHealthScore(score);
        metrics.setHealthStatus(HealthStatus.fromScore(score));
        metrics.setAlerts(generateAlerts(metrics));
    }

    /**
     * 计算健康得分 (0-100)
     */
    private int calculateScore(HealthMetricsData metrics) {
        int score = 0;

        // 储蓄率评分 (最高40分)
        Double savingRate = metrics.getSavingRate();
        if (savingRate != null) {
            if (savingRate >= 30) score += 40;
            else if (savingRate >= 20) score += 35;
            else if (savingRate >= 10) score += 25;
            else if (savingRate >= 0) score += 10;
        }

        // 收支比评分 (最高30分)
        Double ratio = metrics.getIncomeExpenseRatio();
        if (ratio != null) {
            if (ratio <= 0.6) score += 30;
            else if (ratio <= 0.7) score += 25;
            else if (ratio <= 0.85) score += 15;
            else if (ratio <= 0.95) score += 5;
        }

        // 净资产评分 (最高30分)
        Double netSaving = metrics.getTotalNetSaving();
        if (netSaving != null) {
            if (netSaving > 0) score += 30;
            else if (netSaving == 0) score += 10;
        }

        return Math.min(score, 100);
    }

    /**
     * 生成预警信息
     */
    private List<HealthAlert> generateAlerts(HealthMetricsData metrics) {
        List<HealthAlert> alerts = new ArrayList<>();

        // 储蓄率预警
        Double savingRate = metrics.getSavingRate();
        if (savingRate != null) {
            if (savingRate < 0) {
                alerts.add(HealthAlert.danger(
                    "收支逆差",
                    String.format("支出超过收入 %.1f%%", Math.abs(savingRate)),
                    "立即停止非必要消费，审查所有开支项目"
                ));
            } else if (savingRate < 10) {
                alerts.add(HealthAlert.warning(
                    "储蓄率过低",
                    String.format("当前储蓄率仅 %.1f%%，建议提高到 20%% 以上", savingRate),
                    "减少非必要支出，制定储蓄计划"
                ));
            } else if (savingRate < 20) {
                alerts.add(HealthAlert.info(
                    "储蓄率偏低",
                    String.format("当前储蓄率 %.1f%%，仍有提升空间", savingRate)
                ));
            }
        }

        // 收支比预警
        Double ratio = metrics.getIncomeExpenseRatio();
        if (ratio != null && ratio > 1) {
            alerts.add(HealthAlert.danger(
                "收支失衡",
                String.format("支出已超过收入 %.1f%%", (ratio - 1) * 100),
                "紧急建议：暂停所有非必要支出，梳理消费习惯"
            ));
        }

        return alerts;
    }
}
```

