package com.harmony.uspace.dto.statistics;

import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class HealthAlert {
    /** 预警级别 */
    private AlertLevel level;

    /** 预警标题 */
    private String title;

    /** 预警描述 */
    private String description;

    /** 改进建议 */
    private String suggestion;

    /**
     * 创建危险级别预警
     */
    public static HealthAlert danger(String title, String description, String suggestion) {
        return HealthAlert.builder()
                .level(AlertLevel.DANGER)
                .title(title)
                .description(description)
                .suggestion(suggestion)
                .build();
    }

    /**
     * 创建警告级别预警
     */
    public static HealthAlert warning(String title, String description, String suggestion) {
        return HealthAlert.builder()
                .level(AlertLevel.WARNING)
                .title(title)
                .description(description)
                .suggestion(suggestion)
                .build();
    }

    /**
     * 创建信息级别提示
     */
    public static HealthAlert info(String title, String description) {
        return HealthAlert.builder()
                .level(AlertLevel.INFO)
                .title(title)
                .description(description)
                .suggestion(null)
                .build();
    }
}
```

**注意事项:**
- 使用 Lombok 注解: @Data, @Builder, @NoArgsConstructor, @AllArgsConstructor
- 提供三个静态工厂方法: danger(), warning(), info()
- 需要引用 AlertLevel 枚举（已在同包中创建）

