   508→### 6.2 HealthAnalysisEngine.java
   509→
   510→```java
   511→package com.harmony.uspace.service.statistics;
   512→
   513→import com.harmony.uspace.dto.statistics.*;
   514→import lombok.RequiredArgsConstructor;
   515→import lombok.extern.slf4j.Slf4j;
   516→import org.springframework.stereotype.Component;
   517→
   518→import java.util.ArrayList;
   519→import java.util.List;
   520→
   521→/**
   522→ * 财务健康分析引擎
   523→ */
   524→@Slf4j
   525→@Component
   526→@RequiredArgsConstructor
   527→public class HealthAnalysisEngine {
   528→
   529→    /**
   530→     * 计算健康得分和状态
   531→     *
   532→     * @param metrics 健康度指标数据
   533→     */
   534→    public void analyze(HealthMetricsData metrics) {
   535→        int score = calculateScore(metrics);
   536→        metrics.setHealthScore(score);
   537→        metrics.setHealthStatus(HealthStatus.fromScore(score));
   538→        metrics.setAlerts(generateAlerts(metrics));
   539→    }
   540→
   541→    /**
   542→     * 计算健康得分 (0-100)
   543→     */
   544→    private int calculateScore(HealthMetricsData metrics) {
   545→        int score = 0;
   546→
   547→        // 储蓄率评分 (最高40分)
   548→        Double savingRate = metrics.getSavingRate();
   549→        if (savingRate != null) {
   550→            if (savingRate >= 30) score += 40;
   551→            else if (savingRate >= 20) score += 35;
   552→            else if (savingRate >= 10) score += 25;
   553→            else if (savingRate >= 0) score += 10;
   554→        }
   555→
   556→        // 收支比评分 (最高30分)
   557→        Double ratio = metrics.getIncomeExpenseRatio();
   558→        if (ratio != null) {
   559→            if (ratio <= 0.6) score += 30;
   560→            else if (ratio <= 0.7) score += 25;
   561→            else if (ratio <= 0.85) score += 15;
   562→            else if (ratio <= 0.95) score += 5;
   563→        }
   564→
   565→        // 净资产评分 (最高30分)
   566→        Double netSaving = metrics.getTotalNetSaving();
   567→        if (netSaving != null) {
   568→            if (netSaving > 0) score += 30;
   569→            else if (netSaving == 0) score += 10;
   570→        }
   571→
   572→        return Math.min(score, 100);
   573→    }
   574→
   575→    /**
   576→     * 生成预警信息
   577→     */
   578→    private List<HealthAlert> generateAlerts(HealthMetricsData metrics) {
   579→        List<HealthAlert> alerts = new ArrayList<>();
   580→
   581→        // 储蓄率预警
   582→        Double savingRate = metrics.getSavingRate();
   583→        if (savingRate != null) {
   584→            if (savingRate < 0) {
   585→                alerts.add(HealthAlert.danger(
   586→                    "收支逆差",
   587→                    String.format("支出超过收入 %.1f%%", Math.abs(savingRate)),
   588→                    "立即停止非必要消费，审查所有开支项目"
   589→                ));
   590→            } else if (savingRate < 10) {
   591→                alerts.add(HealthAlert.warning(
   592→                    "储蓄率过低",
   593→                    String.format("当前储蓄率仅 %.1f%%，建议提高到 20%% 以上", savingRate),
   594→                    "减少非必要支出，制定储蓄计划"
   595→                ));
   596→            } else if (savingRate < 20) {
   597→                alerts.add(HealthAlert.info(
   598→                    "储蓄率偏低",
   599→                    String.format("当前储蓄率 %.1f%%，仍有提升空间", savingRate)
   600→                ));
   601→            }
   602→        }
   603→
   604→        // 收支比预警
   605→        Double ratio = metrics.getIncomeExpenseRatio();
   606→        if (ratio != null && ratio > 1) {
   607→            alerts.add(HealthAlert.danger(
   608→                "收支失衡",
   609→                String.format("支出已超过收入 %.1f%%", (ratio - 1) * 100),
   610→                "紧急建议：暂停所有非必要支出，梳理消费习惯"
   611→            ));
   612→        }
   613→
   614→        return alerts;
   615→    }
   616→}
