   634→@Component
   635→class StatisticsDao(private val billDocumentRepository: BillDocumentRepository) {
   636→
   637→    /**
   638→     * 获取所有已基础解析完成的账单文档
   639→     */
   640→    fun getResolvedBillDocuments(accountNo: String? = null): List<BillDocument> {
   641→        return if (accountNo.isNullOrBlank()) {
   642→            billDocumentRepository.search {
   643→                where {
   644→                    BillDocument::getBaseResolved `is` true
   645→                }
   646→            }.toElementList()
   647→        } else {
   648→            billDocumentRepository.search {
   649→                where {
   650→                    BillDocument::getBaseResolved `is` true
   651→                    BillDocument::getAccountNo `is` accountNo
   652→                }
   653→            }.toElementList()
   654→        }
   655→    }
   656→
   657→    /**
   658→     * 按月份分组统计账单
   659→     */
   660→    fun getBillsByMonth(accountNo: String? = null): Map<String, List<BillDocument>> {
   661→        return getResolvedBillDocuments(accountNo)
   662→            .groupBy { bill ->
   663→                bill.startTime?.format(DateTimeFormatter.ofPattern("yyyy-MM")) ?: "unknown"
   664→            }
   665→    }
   666→}
