   173→                    .build();
   174→        }
   175→
   176→        // Calculate monthly expenses
   177→        List<MonthlyExpenseData> monthlyExpenses = billsByMonth.entrySet().stream()
   178→                .map(entry -> {
   179→                    String month = entry.getKey();
   180→                    double expense = entry.getValue().stream()
   181→                            .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
   182→                            .sum();
   183→                    return new MonthlyExpenseData(month, expense);
   184→                })
   185→                .sorted(Comparator.comparing(MonthlyExpenseData::getMonth))
   186→                .collect(Collectors.toList());
   187→
   188→        // Calculate statistics
   189→        double meanExpense = monthlyExpenses.stream()
   190→                .mapToDouble(MonthlyExpenseData::getExpense)
   191→                .average()
   192→                .orElse(0.0);
   193→
   194→        double variance = monthlyExpenses.stream()
   195→                .mapToDouble(data -> Math.pow(data.getExpense() - meanExpense, 2))
   196→                .average()
   197→                .orElse(0.0);
   198→
   199→        double stdDeviation = Math.sqrt(variance);
   200→
   201→        double maxExpense = monthlyExpenses.stream()
   202→                .mapToDouble(MonthlyExpenseData::getExpense)
   203→                .max()
   204→                .orElse(0.0);
   205→
   206→        double minExpense = monthlyExpenses.stream()
   207→                .mapToDouble(MonthlyExpenseData::getExpense)
   208→                .min()
   209→                .orElse(0.0);
   210→
   211→        double volatilityRate = meanExpense > 0 ? stdDeviation / meanExpense : 0.0;
   212→
   213→        // Build monthly volatility data
   214→        List<MonthlyVolatility> monthlyData = monthlyExpenses.stream()
   215→                .map(data -> {
   216→                    double deviationFromMean = data.getExpense() - meanExpense;
   217→                    double deviationPercent = meanExpense > 0 ? (deviationFromMean / meanExpense) * 100 : 0.0;
   218→                    VolatilityLevel level = determineVolatilityLevel(deviationFromMean, stdDeviation);
