   247→        return VolatilityAnalysisData.builder()
   248→                .meanExpense(round(meanExpense))
   249→                .stdDeviation(round(stdDeviation))
   250→                .volatilityRate(round(volatilityRate))
   251→                .maxExpense(round(maxExpense))
   252→                .minExpense(round(minExpense))
   253→                .expenseRange(round(maxExpense - minExpense))
   254→                .monthlyData(monthlyData)
   255→                .highExpenseMonths(highExpenseMonths)
   256→                .lowExpenseMonths(lowExpenseMonths)
   257→                .volatilityAssessment(volatilityAssessment)
   258→                .build();
   259→    }
