   274→            return StatisticsOverview.builder()
   275→                    .health(HealthMetricsData.builder().build())
   276→                    .recentTrend(Collections.emptyList())
   277→                    .totalBills(0)
   278→                    .totalMonths(0)
   279→                    .accounts(Collections.emptyList())
   280→                    .build();
