   282→
   283→        // Get health metrics
   284→        HealthMetricsData health = getHealthMetrics(accountNo);
   285→
   286→        // Get recent 6 months trend
   287→        List<MonthlyTrendData> recentTrend = getMonthlyTrend(accountNo, 6);
   288→
   289→        // Calculate date range
   290→        LocalDate startDate = bills.stream()
   291→                .map(BillDocument::getStartTime)
   292→                .filter(Objects::nonNull)
   293→                .map(LocalDateTime::toLocalDate)
   294→                .min(LocalDate::compareTo)
   295→                .orElse(null);
   296→
   297→        LocalDate endDate = bills.stream()
   298→                .map(BillDocument::getEndTime)
   299→                .filter(Objects::nonNull)
   300→                .map(LocalDateTime::toLocalDate)
   301→                .max(LocalDate::compareTo)
   302→                .orElse(null);
   303→
   304→        // Get unique accounts
   305→        List<String> accounts = bills.stream()
   306→                .map(BillDocument::getAccountNo)
   307→                .filter(Objects::nonNull)
   308→                .distinct()
   309→                .collect(Collectors.toList());
   310→
   311→        // Get unique months count
   312→        int totalMonths = (int) bills.stream()
   313→                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
   314→                .distinct()
   315→                .count();
   316→
   317→        return StatisticsOverview.builder()
   318→                .health(health)
   319→                .recentTrend(recentTrend)
   320→                .dataStartDate(startDate)
   321→                .dataEndDate(endDate)
   322→                .totalBills(bills.size())
   323→                .totalMonths(totalMonths)
   324→                .accounts(accounts)
   325→                .build();
   326→    }
