   328→    /**
   329→     * 确定波动级别
   330→     */
   331→    private VolatilityLevel determineVolatilityLevel(double deviation, double stdDev) {
   332→        double absDeviation = Math.abs(deviation);
   333→        if (absDeviation > 2 * stdDev) {
   334→            return VolatilityLevel.EXTREME;
   335→        } else if (absDeviation > stdDev) {
   336→            return VolatilityLevel.HIGH;
   337→        } else {
   338→            return VolatilityLevel.LOW;
   339→        }
   340→    }
   341→
   342→    /**
   343→     * 生成波动性评价
   344→     */
   345→    private String generateVolatilityAssessment(double volatilityRate) {
   346→        if (volatilityRate < 0.1) {
   347→            return "消费非常稳定，波动很小";
   348→        } else if (volatilityRate < 0.2) {
   349→            return "消费较为稳定，波动在正常范围内";
   350→        } else if (volatilityRate < 0.3) {
   351→            return "消费波动偏高，建议关注异常支出";
   352→        } else {
   353→            return "消费波动异常，建议审查消费习惯";
   354→        }
   355→    }
   356→
   357→    /**
   358→     * 四舍五入到2位小数
   359→     */
   360→    private double round(double value) {
   361→        return BigDecimal.valueOf(value)
   362→                .setScale(2, RoundingMode.HALF_UP)
   363→                .doubleValue();
   364→    }
   365→
