    18→/**
    19→ * 账单文档统计服务
    20→ */
    21→@Slf4j
    22→@Service
    23→@RequiredArgsConstructor
    24→public class BillDocumentStatisticsService {
    25→
    26→    private final StatisticsDao statisticsDao;
    27→    private final HealthAnalysisEngine healthAnalysisEngine;
    28→
    29→    private static final DateTimeFormatter MONTH_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM");
    30→
    31→    /**
    32→     * 获取月度收支趋势
    33→     *
    34→     * @param accountNo 账号（可选）
    35→     * @param months 获取最近N个月
    36→     * @return 月度趋势数据列表
    37→     */
    38→    public List<MonthlyTrendData> getMonthlyTrend(String accountNo, int months) {
    39→        log.debug("Getting monthly trend for account: {}, months: {}", accountNo, months);
    40→
    41→        Map<String, List<BillDocument>> billsByMonth = statisticsDao.getBillsByMonth(accountNo);
    42→
    43→        List<MonthlyTrendData> trendData = billsByMonth.entrySet().stream()
    44→                .map(entry -> {
    45→                    String month = entry.getKey();
    46→                    List<BillDocument> bills = entry.getValue();
    47→
    48→                    double income = bills.stream()
    49→                            .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
    50→                            .sum();
    51→
    52→                    double expense = bills.stream()
    53→                            .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
    54→                            .sum();
    55→
    56→                    double netSaving = income - expense;
    57→                    int billCount = bills.size();
    58→
    59→                    return MonthlyTrendData.builder()
    60→                            .month(month)
    61→                            .income(income)
    62→                            .expense(expense)
    63→                            .netSaving(netSaving)
    64→                            .billCount(billCount)
    65→                            .build();
    66→                })
    67→                .sorted(Comparator.comparing(MonthlyTrendData::getMonth).reversed())
    68→                .limit(months)
    69→                .sorted(Comparator.comparing(MonthlyTrendData::getMonth))
    70→                .collect(Collectors.toList());
    71→
    72→        log.debug("Returning {} months of trend data", trendData.size());
    73→        return trendData;
    74→    }
    75→
    76→    /**
    77→     * 获取健康度指标
    78→     *
    79→     * @param accountNo 账号（可选）
    80→     * @return 健康度指标数据
    81→     */
    82→    public HealthMetricsData getHealthMetrics(String accountNo) {
    83→        log.debug("Getting health metrics for account: {}", accountNo);
    84→
    85→        List<BillDocument> bills = statisticsDao.getResolvedBillDocuments(accountNo);
    86→
    87→        if (bills.isEmpty()) {
    88→            log.warn("No resolved bills found for account: {}", accountNo);
    89→            return HealthMetricsData.builder()
    90→                    .avgMonthlyIncome(0.0)
    91→                    .avgMonthlyExpense(0.0)
    92→                    .savingRate(0.0)
    93→                    .incomeExpenseRatio(0.0)
    94→                    .totalNetSaving(0.0)
    95→                    .monthsCovered(0)
    96→                    .healthScore(0)
    97→                    .alerts(Collections.emptyList())
    98→                    .build();
    99→        }
   100→
   101→        // Calculate totals
   102→        double totalIncome = bills.stream()
   103→                .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
   104→                .sum();
   105→
   106→        double totalExpense = bills.stream()
   107→                .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
   108→                .sum();
   109→
   110→        // Get unique months count
   111→        Set<String> uniqueMonths = bills.stream()
   112→                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
   113→                .collect(Collectors.toSet());
   114→
   115→        int monthsCount = uniqueMonths.size();
   116→
   117→        // Calculate metrics
   118→        double avgMonthlyIncome = monthsCount > 0 ? totalIncome / monthsCount : 0.0;
   119→        double avgMonthlyExpense = monthsCount > 0 ? totalExpense / monthsCount : 0.0;
   120→        double totalNetSaving = totalIncome - totalExpense;
   121→        double savingRate = totalIncome > 0 ? (totalNetSaving / totalIncome) * 100 : 0.0;
   122→        double incomeExpenseRatio = totalIncome > 0 ? totalExpense / totalIncome : 0.0;
   123→
   124→        // Round to 2 decimal places
   125→        avgMonthlyIncome = round(avgMonthlyIncome);
   126→        avgMonthlyExpense = round(avgMonthlyExpense);
   127→        totalNetSaving = round(totalNetSaving);
   128→        savingRate = round(savingRate);
   129→        incomeExpenseRatio = round(incomeExpenseRatio);
   130→
   131→        HealthMetricsData metrics = HealthMetricsData.builder()
   132→                .avgMonthlyIncome(avgMonthlyIncome)
   133→                .avgMonthlyExpense(avgMonthlyExpense)
   134→                .savingRate(savingRate)
   135→                .incomeExpenseRatio(incomeExpenseRatio)
   136→                .totalNetSaving(totalNetSaving)
   137→                .monthsCovered(monthsCount)
   138→                .build();
   139→
   140→        // Run health analysis
   141→        healthAnalysisEngine.analyze(metrics);
   142→
   143→        log.debug("Health metrics calculated - Score: {}, Status: {}",
   144→                metrics.getHealthScore(), metrics.getHealthStatus());
   145→
   146→        return metrics;
   147→    }
   148→
   149→    /**
   150→     * 获取消费波动分析
   151→     *
   152→     * @param accountNo 账号（可选）
   153→     * @return 波动分析数据
   154→     */
   155→    public VolatilityAnalysisData getVolatilityAnalysis(String accountNo) {
   156→        log.debug("Getting volatility analysis for account: {}", accountNo);
   157→
   158→        Map<String, List<BillDocument>> billsByMonth = statisticsDao.getBillsByMonth(accountNo);
   159→
   160→        if (billsByMonth.isEmpty()) {
   161→            log.warn("No bills found for volatility analysis for account: {}", accountNo);
   162→            return VolatilityAnalysisData.builder()
   163→                    .meanExpense(0.0)
   164→                    .stdDeviation(0.0)
   165→                    .volatilityRate(0.0)
   166→                    .maxExpense(0.0)
   167→                    .minExpense(0.0)
   168→                    .expenseRange(0.0)
   169→                    .monthlyData(Collections.emptyList())
   170→                    .highExpenseMonths(Collections.emptyList())
   171→                    .lowExpenseMonths(Collections.emptyList())
   172→                    .volatilityAssessment("暂无数据")
   173→                    .build();
   174→        }
   175→
   176→        // Calculate monthly expenses
   177→        List<MonthlyExpenseData> monthlyExpenses = billsByMonth.entrySet().stream()
   178→                .map(entry -> {
   179→                    String month = entry.getKey();
   180→                    double expense = entry.getValue().stream()
   181→                            .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
   182→                            .sum();
   183→                    return new MonthlyExpenseData(month, expense);
   184→                })
   185→                .sorted(Comparator.comparing(MonthlyExpenseData::getMonth))
   186→                .collect(Collectors.toList());
   187→
   188→        // Calculate statistics
   189→        double meanExpense = monthlyExpenses.stream()
   190→                .mapToDouble(MonthlyExpenseData::getExpense)
   191→                .average()
   192→                .orElse(0.0);
   193→
   194→        double variance = monthlyExpenses.stream()
   195→                .mapToDouble(data -> Math.pow(data.getExpense() - meanExpense, 2))
   196→                .average()
   197→                .orElse(0.0);
   198→
   199→        double stdDeviation = Math.sqrt(variance);
   200→
   201→        double maxExpense = monthlyExpenses.stream()
   202→                .mapToDouble(MonthlyExpenseData::getExpense)
   203→                .max()
   204→                .orElse(0.0);
   205→
   206→        double minExpense = monthlyExpenses.stream()
   207→                .mapToDouble(MonthlyExpenseData::getExpense)
   208→                .min()
   209→                .orElse(0.0);
   210→
   211→        double volatilityRate = meanExpense > 0 ? stdDeviation / meanExpense : 0.0;
   212→
   213→        // Build monthly volatility data
   214→        List<MonthlyVolatility> monthlyData = monthlyExpenses.stream()
   215→                .map(data -> {
   216→                    double deviationFromMean = data.getExpense() - meanExpense;
   217→                    double deviationPercent = meanExpense > 0 ? (deviationFromMean / meanExpense) * 100 : 0.0;
   218→                    VolatilityLevel level = determineVolatilityLevel(deviationFromMean, stdDeviation);
   219→
   220→                    return MonthlyVolatility.builder()
   221→                            .month(data.getMonth())
   222→                            .expense(data.getExpense())
   223→                            .deviationFromMean(round(deviationFromMean))
   224→                            .deviationPercent(round(deviationPercent))
   225→                            .level(level)
   226→                            .build();
   227→                })
   228→                .collect(Collectors.toList());
   229→
   230→        // Identify high and low expense months
   231→        double upperThreshold = meanExpense + stdDeviation;
   232→        double lowerThreshold = meanExpense - stdDeviation;
   233→
   234→        List<String> highExpenseMonths = monthlyExpenses.stream()
   235→                .filter(data -> data.getExpense() > upperThreshold)
   236→                .map(MonthlyExpenseData::getMonth)
   237→                .collect(Collectors.toList());
   238→
   239→        List<String> lowExpenseMonths = monthlyExpenses.stream()
   240→                .filter(data -> data.getExpense() < lowerThreshold)
   241→                .map(MonthlyExpenseData::getMonth)
   242→                .collect(Collectors.toList());
   243→
   244→        // Generate volatility assessment
   245→        String volatilityAssessment = generateVolatilityAssessment(volatilityRate);
   246→
   247→        return VolatilityAnalysisData.builder()
   248→                .meanExpense(round(meanExpense))
   249→                .stdDeviation(round(stdDeviation))
   250→                .volatilityRate(round(volatilityRate))
   251→                .maxExpense(round(maxExpense))
   252→                .minExpense(round(minExpense))
   253→                .expenseRange(round(maxExpense - minExpense))
   254→                .monthlyData(monthlyData)
   255→                .highExpenseMonths(highExpenseMonths)
   256→                .lowExpenseMonths(lowExpenseMonths)
   257→                .volatilityAssessment(volatilityAssessment)
   258→                .build();
   259→    }
   260→
   261→    /**
   262→     * 获取统计总览
   263→     *
   264→     * @param accountNo 账号（可选）
   265→     * @return 统计总览数据
   266→     */
   267→    public StatisticsOverview getOverview(String accountNo) {
   268→        log.debug("Getting statistics overview for account: {}", accountNo);
   269→
   270→        List<BillDocument> bills = statisticsDao.getResolvedBillDocuments(accountNo);
   271→
   272→        if (bills.isEmpty()) {
   273→            log.warn("No bills found for overview for account: {}", accountNo);
   274→            return StatisticsOverview.builder()
   275→                    .health(HealthMetricsData.builder().build())
   276→                    .recentTrend(Collections.emptyList())
   277→                    .totalBills(0)
   278→                    .totalMonths(0)
   279→                    .accounts(Collections.emptyList())
   280→                    .build();
   281→        }
   282→
   283→        // Get health metrics
   284→        HealthMetricsData health = getHealthMetrics(accountNo);
   285→
   286→        // Get recent 6 months trend
   287→        List<MonthlyTrendData> recentTrend = getMonthlyTrend(accountNo, 6);
   288→
   289→        // Calculate date range
   290→        LocalDate startDate = bills.stream()
   291→                .map(BillDocument::getStartTime)
   292→                .filter(Objects::nonNull)
   293→                .map(LocalDateTime::toLocalDate)
   294→                .min(LocalDate::compareTo)
   295→                .orElse(null);
   296→
   297→        LocalDate endDate = bills.stream()
   298→                .map(BillDocument::getEndTime)
   299→                .filter(Objects::nonNull)
   300→                .map(LocalDateTime::toLocalDate)
   301→                .max(LocalDate::compareTo)
   302→                .orElse(null);
   303→
   304→        // Get unique accounts
   305→        List<String> accounts = bills.stream()
   306→                .map(BillDocument::getAccountNo)
   307→                .filter(Objects::nonNull)
   308→                .distinct()
   309→                .collect(Collectors.toList());
   310→
   311→        // Get unique months count
   312→        int totalMonths = (int) bills.stream()
   313→                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
   314→                .distinct()
   315→                .count();
   316→
   317→        return StatisticsOverview.builder()
   318→                .health(health)
   319→                .recentTrend(recentTrend)
   320→                .dataStartDate(startDate)
   321→                .dataEndDate(endDate)
   322→                .totalBills(bills.size())
   323→                .totalMonths(totalMonths)
   324→                .accounts(accounts)
   325→                .build();
   326→    }
   327→
   328→    /**
   329→     * 确定波动级别
   330→     */
   331→    private VolatilityLevel determineVolatilityLevel(double deviation, double stdDev) {
   332→        double absDeviation = Math.abs(deviation);
   333→        if (absDeviation > 2 * stdDev) {
   334→            return VolatilityLevel.EXTREME;
   335→        } else if (absDeviation > stdDev) {
   336→            return VolatilityLevel.HIGH;
   337→        } else {
   338→            return VolatilityLevel.LOW;
   339→        }
   340→    }
   341→
   342→    /**
   343→     * 生成波动性评价
   344→     */
   345→    private String generateVolatilityAssessment(double volatilityRate) {
   346→        if (volatilityRate < 0.1) {
   347→            return "消费非常稳定，波动很小";
   348→        } else if (volatilityRate < 0.2) {
   349→            return "消费较为稳定，波动在正常范围内";
   350→        } else if (volatilityRate < 0.3) {
   351→            return "消费波动偏高，建议关注异常支出";
   352→        } else {
   353→            return "消费波动异常，建议审查消费习惯";
   354→        }
   355→    }
   356→
   357→    /**
   358→     * 四舍五入到2位小数
   359→     */
   360→    private double round(double value) {
   361→        return BigDecimal.valueOf(value)
   362→                .setScale(2, RoundingMode.HALF_UP)
   363→                .doubleValue();
   364→    }
   365→
   366→    /**
   367→     * 内部类：月度支出数据
   368→     */
   369→    private static class MonthlyExpenseData {
   370→        private final String month;
   371→        private final double expense;
   372→
   373→        public MonthlyExpenseData(String month, double expense) {
   374→            this.month = month;
   375→            this.expense = expense;
   376→        }
   377→
   378→        public String getMonth() {
   379→            return month;
   380→        }
   381→
   382→        public double getExpense() {
   383→            return expense;
   384→        }
   385→    }
   386→}
