package com.harmony.uspace.service.statistics;

import com.harmony.uspace.dto.statistics.AlertLevel;
import com.harmony.uspace.dto.statistics.HealthAlert;
import com.harmony.uspace.dto.statistics.HealthMetricsData;
import com.harmony.uspace.dto.statistics.HealthStatus;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * HealthAnalysisEngine 单元测试
 *
 * 测试财务健康分析引擎的各项功能，包括：
 * - 健康得分计算
 * - 健康状态判定
 * - 预警信息生成
 * - 完整分析流程
 */
@DisplayName("财务健康分析引擎测试")
class HealthAnalysisEngineTest {

    private HealthAnalysisEngine engine;

    @BeforeEach
    void setUp() {
        engine = new HealthAnalysisEngine();
    }

    @Test
    @DisplayName("测试优秀状态 - 储蓄率>=30%, 收支比<=0.6, 净资产>0")
    void testCalculateScore_ExcellentStatus() {
        // Given: 创建优秀状态的指标数据
        HealthMetricsData metrics = HealthMetricsData.builder()
                .avgMonthlyIncome(10000.0)
                .avgMonthlyExpense(6000.0)
                .savingRate(40.0)  // 40% 储蓄率
                .incomeExpenseRatio(0.6)  // 0.6 收支比
                .totalNetSaving(50000.0)  // 正净资产
                .build();

        // When: 执行分析
        engine.analyze(metrics);

        // Then: 验证结果
        assertNotNull(metrics.getHealthScore(), "健康得分不应为空");
        assertTrue(metrics.getHealthScore() >= 80,
                "优秀状态得分应 >= 80，实际得分: " + metrics.getHealthScore());
        assertEquals(HealthStatus.EXCELLENT, metrics.getHealthStatus(),
                "健康状态应为 EXCELLENT");
        assertTrue(metrics.getHealthScore() == 100,
                "满分情况应得100分，实际得分: " + metrics.getHealthScore());
    }

    @Test
    @DisplayName("测试良好状态 - 储蓄率>=20%, 收支比<=0.7")
    void testCalculateScore_GoodStatus() {
        // Given: 创建良好状态的指标数据
        HealthMetricsData metrics = HealthMetricsData.builder()
                .avgMonthlyIncome(10000.0)
                .avgMonthlyExpense(7500.0)
                .savingRate(25.0)  // 25% 储蓄率
                .incomeExpenseRatio(0.7)  // 0.7 收支比
                .totalNetSaving(30000.0)  // 正净资产
                .build();

        // When: 执行分析
        engine.analyze(metrics);

        // Then: 验证结果
        assertNotNull(metrics.getHealthScore(), "健康得分不应为空");
        assertTrue(metrics.getHealthScore() >= 60,
                "良好状态得分应 >= 60，实际得分: " + metrics.getHealthScore());
        assertEquals(HealthStatus.GOOD, metrics.getHealthStatus(),
                "健康状态应为 GOOD");
        // 储蓄率25分 + 收支比25分 + 净资产30分 = 80分
        assertEquals(80, metrics.getHealthScore(),
                "预期得分应为80分");
    }

    @Test
    @DisplayName("测试预警状态 - 储蓄率<10%, 收支比接近1")
    void testCalculateScore_WarningStatus() {
        // Given: 创建预警状态的指标数据
        HealthMetricsData metrics = HealthMetricsData.builder()
                .avgMonthlyIncome(10000.0)
                .avgMonthlyExpense(9200.0)
                .savingRate(8.0)  // 8% 储蓄率
                .incomeExpenseRatio(0.92)  // 0.92 收支比
                .totalNetSaving(5000.0)  // 正净资产
                .build();

        // When: 执行分析
        engine.analyze(metrics);

        // Then: 验证结果
        assertNotNull(metrics.getHealthScore(), "健康得分不应为空");
        assertTrue(metrics.getHealthScore() < 60,
                "预警状态得分应 < 60，实际得分: " + metrics.getHealthScore());
        // 储蓄率10分 + 收支比5分 + 净资产30分 = 45分
        assertEquals(45, metrics.getHealthScore(),
                "预期得分应为45分");
        assertEquals(HealthStatus.WARNING, metrics.getHealthStatus(),
                "健康状态应为 WARNING");
    }

