    12→
    13→/**
    14→ * 财务健康分析引擎
    15→ */
    16→@Slf4j
    17→@Component
    18→@RequiredArgsConstructor
    19→public class HealthAnalysisEngine {
    20→
    21→    /**
    22→     * 计算健康得分和状态
    23→     *
    24→     * @param metrics 健康度指标数据
    25→     */
    26→    public void analyze(HealthMetricsData metrics) {
    27→        int score = calculateScore(metrics);
    28→        metrics.setHealthScore(score);
    29→        metrics.setHealthStatus(HealthStatus.fromScore(score));
    30→        metrics.setAlerts(generateAlerts(metrics));
    31→    }
    32→
    33→    /**
    34→     * 计算健康得分 (0-100)
    35→     */
    36→    private int calculateScore(HealthMetricsData metrics) {
    37→        int score = 0;
    38→
    39→        // 储蓄率评分 (最高40分)
    40→        Double savingRate = metrics.getSavingRate();
    41→        if (savingRate != null) {
    42→            if (savingRate >= 30) score += 40;
    43→            else if (savingRate >= 20) score += 35;
    44→            else if (savingRate >= 10) score += 25;
    45→            else if (savingRate >= 0) score += 10;
    46→        }
    47→
    48→        // 收支比评分 (最高30分)
    49→        Double ratio = metrics.getIncomeExpenseRatio();
    50→        if (ratio != null) {
    51→            if (ratio <= 0.6) score += 30;
    52→            else if (ratio <= 0.7) score += 25;
    53→            else if (ratio <= 0.85) score += 15;
    54→            else if (ratio <= 0.95) score += 5;
    55→        }
    56→
    57→        // 净资产评分 (最高30分)
    58→        Double netSaving = metrics.getTotalNetSaving();
    59→        if (netSaving != null) {
    60→            if (netSaving > 0) score += 30;
    61→            else if (netSaving == 0) score += 10;
    62→        }
    63→
    64→        return Math.min(score, 100);
    65→    }
    66→
    67→    /**
    68→     * 生成预警信息
    69→     */
    70→    private List<HealthAlert> generateAlerts(HealthMetricsData metrics) {
    71→        List<HealthAlert> alerts = new ArrayList<>();
    72→
    73→        // 储蓄率预警
    74→        Double savingRate = metrics.getSavingRate();
    75→        if (savingRate != null) {
    76→            if (savingRate < 0) {
    77→                alerts.add(HealthAlert.danger(
    78→                    "收支逆差",
    79→                    String.format("支出超过收入 %.1f%%", Math.abs(savingRate)),
    80→                    "立即停止非必要消费，审查所有开支项目"
    81→                ));
    82→            } else if (savingRate < 10) {
    83→                alerts.add(HealthAlert.warning(
    84→                    "储蓄率过低",
    85→                    String.format("当前储蓄率仅 %.1f%%，建议提高到 20%% 以上", savingRate),
    86→                    "减少非必要支出，制定储蓄计划"
    87→                ));
    88→            } else if (savingRate < 20) {
    89→                alerts.add(HealthAlert.info(
    90→                    "储蓄率偏低",
    91→                    String.format("当前储蓄率 %.1f%%，仍有提升空间", savingRate)
    92→                ));
    93→            }
    94→        }
    95→
    96→        // 收支比预警
    97→        Double ratio = metrics.getIncomeExpenseRatio();
    98→        if (ratio != null && ratio > 1) {
    99→            alerts.add(HealthAlert.danger(
   100→                "收支失衡",
   101→                String.format("支出已超过收入 %.1f%%", (ratio - 1) * 100),
   102→                "紧急建议：暂停所有非必要支出，梳理消费习惯"
   103→            ));
   104→        }
   105→
   106→        return alerts;
   107→    }
   108→}
