    18→/**
    19→ * 账单文档统计服务
    20→ */
    21→@Slf4j
    22→@Service
    23→@RequiredArgsConstructor
    24→public class BillDocumentStatisticsService {
    25→
    26→    private final StatisticsDao statisticsDao;
    27→    private final HealthAnalysisEngine healthAnalysisEngine;
    28→
    29→    private static final DateTimeFormatter MONTH_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM");
    30→
    31→    /**
    32→     * 获取月度收支趋势
    33→     *
    34→     * @param accountNo 账号（可选）
    35→     * @param months 获取最近N个月
    36→     * @return 月度趋势数据列表
    37→     */
    38→    public List<MonthlyTrendData> getMonthlyTrend(String accountNo, int months) {
    39→        log.debug("Getting monthly trend for account: {}, months: {}", accountNo, months);
    40→
    41→        Map<String, List<BillDocument>> billsByMonth = statisticsDao.getBillsByMonth(accountNo);
    42→
    43→        List<MonthlyTrendData> trendData = billsByMonth.entrySet().stream()
    44→                .map(entry -> {
    45→                    String month = entry.getKey();
    46→                    List<BillDocument> bills = entry.getValue();
    47→
    48→                    double income = bills.stream()
    49→                            .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
    50→                            .sum();
    51→
    52→                    double expense = bills.stream()
    53→                            .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
    54→                            .sum();
    55→
    56→                    double netSaving = income - expense;
    57→                    int billCount = bills.size();
    58→
    59→                    return MonthlyTrendData.builder()
    60→                            .month(month)
    61→                            .income(income)
    62→                            .expense(expense)
    63→                            .netSaving(netSaving)
    64→                            .billCount(billCount)
    65→                            .build();
    66→                })
    67→                .sorted(Comparator.comparing(MonthlyTrendData::getMonth).reversed())
    68→                .limit(months)
    69→                .sorted(Comparator.comparing(MonthlyTrendData::getMonth))
    70→                .collect(Collectors.toList());
    71→
    72→        log.debug("Returning {} months of trend data", trendData.size());
    73→        return trendData;
    74→    }
    75→
    76→    /**
    77→     * 获取健康度指标
    78→     *
    79→     * @param accountNo 账号（可选）
    80→     * @return 健康度指标数据
    81→     */
    82→    public HealthMetricsData getHealthMetrics(String accountNo) {
    83→        log.debug("Getting health metrics for account: {}", accountNo);
    84→
    85→        List<BillDocument> bills = statisticsDao.getResolvedBillDocuments(accountNo);
    86→
    87→        if (bills.isEmpty()) {
    88→            log.warn("No resolved bills found for account: {}", accountNo);
    89→            return HealthMetricsData.builder()
    90→                    .avgMonthlyIncome(0.0)
    91→                    .avgMonthlyExpense(0.0)
    92→                    .savingRate(0.0)
    93→                    .incomeExpenseRatio(0.0)
    94→                    .totalNetSaving(0.0)
    95→                    .monthsCovered(0)
    96→                    .healthScore(0)
    97→                    .alerts(Collections.emptyList())
    98→                    .build();
    99→        }
   100→
   101→        // Calculate totals
   102→        double totalIncome = bills.stream()
   103→                .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
   104→                .sum();
   105→
   106→        double totalExpense = bills.stream()
   107→                .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
   108→                .sum();
   109→
   110→        // Get unique months count
   111→        Set<String> uniqueMonths = bills.stream()
   112→                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
   113→                .collect(Collectors.toSet());
   114→
   115→        int monthsCount = uniqueMonths.size();
   116→
   117→        // Calculate metrics
   118→        double avgMonthlyIncome = monthsCount > 0 ? totalIncome / monthsCount : 0.0;
   119→        double avgMonthlyExpense = monthsCount > 0 ? totalExpense / monthsCount : 0.0;
   120→        double totalNetSaving = totalIncome - totalExpense;
   121→        double savingRate = totalIncome > 0 ? (totalNetSaving / totalIncome) * 100 : 0.0;
   122→        double incomeExpenseRatio = totalIncome > 0 ? totalExpense / totalIncome : 0.0;
   123→
   124→        // Round to 2 decimal places
   125→        avgMonthlyIncome = round(avgMonthlyIncome);
   126→        avgMonthlyExpense = round(avgMonthlyExpense);
   127→        totalNetSaving = round(totalNetSaving);
   128→        savingRate = round(savingRate);
   129→        incomeExpenseRatio = round(incomeExpenseRatio);
   130→
   131→        HealthMetricsData metrics = HealthMetricsData.builder()
   132→                .avgMonthlyIncome(avgMonthlyIncome)
   133→                .avgMonthlyExpense(avgMonthlyExpense)
   134→                .savingRate(savingRate)
   135→                .incomeExpenseRatio(incomeExpenseRatio)
   136→                .totalNetSaving(totalNetSaving)
   137→                .monthsCovered(monthsCount)
   138→                .build();
   139→
   140→        // Run health analysis
   141→        healthAnalysisEngine.analyze(metrics);
   142→
   143→        log.debug("Health metrics calculated - Score: {}, Status: {}",
   144→                metrics.getHealthScore(), metrics.getHealthStatus());
   145→
   146→        return metrics;
   147→    }
