    20→    fun getResolvedBillDocuments(accountNo: String? = null): List<BillDocument> {
    21→        return if (accountNo.isNullOrBlank()) {
    22→            billDocumentRepository.search {
    23→                where {
    24→                    BillDocument::getBaseResolved `is` true
    25→                }
    26→            }.toElementList()
    27→        } else {
    28→            billDocumentRepository.search {
    29→                where {
    30→                    BillDocument::getBaseResolved `is` true
    31→                    BillDocument::getAccountNo `is` accountNo
    32→                }
    33→            }.toElementList()
    34→        }
    35→    }
    36→
    37→    /**
    38→     * 按月份分组统计账单
    39→     */
    40→    fun getBillsByMonth(accountNo: String? = null): Map<String, List<BillDocument>> {
    41→        return getResolvedBillDocuments(accountNo)
    42→            .groupBy { bill ->
    43→                bill.startTime?.format(monthFormatter) ?: "unknown"
    44→            }
    45→    }
    46→}
