     5→@Getter
     6→public enum HealthStatus {
     7→    EXCELLENT("excellent", "🟢", "优秀", 80),
     8→    GOOD("good", "🟡", "良好", 60),
     9→    WARNING("warning", "🟠", "预警", 40),
    10→    DANGER("danger", "🔴", "危险", 0);
    11→
    12→    private final String code;
    13→    private final String icon;
    14→    private final String label;
    15→    private final int scoreThreshold;
    16→
    17→    HealthStatus(String code, String icon, String label, int scoreThreshold) {
    18→        this.code = code;
    19→        this.icon = icon;
    20→        this.label = label;
    21→        this.scoreThreshold = scoreThreshold;
    22→    }
    23→
    24→    public static HealthStatus fromScore(int score) {
    25→        if (score >= EXCELLENT.scoreThreshold) return EXCELLENT;
    26→        if (score >= GOOD.scoreThreshold) return GOOD;
    27→        if (score >= WARNING.scoreThreshold) return WARNING;
    28→        return DANGER;
    29→    }
    30→}
