package com.harmony.uspace.service.statistics;

import com.harmony.uspace.domain.BillDocument;
import com.harmony.uspace.dto.statistics.*;
import com.harmony.uspace.dto.statistics.VolatilityLevel;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.time.LocalDateTime;
import java.time.LocalDate;
import java.util.*;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.isNull;
import static org.mockito.Mockito.*;

/**
 * BillDocumentStatisticsService 单元测试
 *
 * 测试账单文档统计服务的各项功能，包括：
 * - 月度趋势计算
 * - 健康度指标计算
 * - 波动分析计算
 * - 统计总览计算
 * - 边界情况和空值处理
 */
@DisplayName("账单文档统计服务测试")
@ExtendWith(MockitoExtension.class)
class BillDocumentStatisticsServiceTest {

    @Mock
    private StatisticsDao statisticsDao;

    @Mock
    private HealthAnalysisEngine healthAnalysisEngine;

    @InjectMocks
    private BillDocumentStatisticsService service;

    private List<BillDocument> testBills;
    private Map<String, List<BillDocument>> billsByMonth;

    @BeforeEach
    void setUp() {
        // 准备测试数据
        testBills = createTestBills();
        billsByMonth = createBillsByMonth();
    }

    /**
     * 创建测试用的账单数据
     */
    private List<BillDocument> createTestBills() {
        List<BillDocument> bills = new ArrayList<>();

        // 2024-01月数据
        bills.add(createBill("acc001", "2024-01-01", "2024-01-31", 10000.0, 6000.0));
        bills.add(createBill("acc001", "2024-01-01", "2024-01-31", 2000.0, 1500.0));

        // 2024-02月数据
        bills.add(createBill("acc001", "2024-02-01", "2024-02-29", 12000.0, 7000.0));
        bills.add(createBill("acc001", "2024-02-01", "2024-02-29", 3000.0, 2000.0));

        // 2024-03月数据
        bills.add(createBill("acc001", "2024-03-01", "2024-03-31", 9000.0, 8000.0));

        return bills;
    }

    /**
     * 创建按月份分组的账单数据
     */
    private Map<String, List<BillDocument>> createBillsByMonth() {
        Map<String, List<BillDocument>> map = new LinkedHashMap<>();

        // 2024-01月
        List<BillDocument> janBills = new ArrayList<>();
        janBills.add(createBill("acc001", "2024-01-01", "2024-01-31", 10000.0, 6000.0));
        janBills.add(createBill("acc001", "2024-01-01", "2024-01-31", 2000.0, 1500.0));
        map.put("2024-01", janBills);

        // 2024-02月
        List<BillDocument> febBills = new ArrayList<>();
        febBills.add(createBill("acc001", "2024-02-01", "2024-02-29", 12000.0, 7000.0));
        febBills.add(createBill("acc001", "2024-02-01", "2024-02-29", 3000.0, 2000.0));
        map.put("2024-02", febBills);

        // 2024-03月
        List<BillDocument> marBills = new ArrayList<>();
        marBills.add(createBill("acc001", "2024-03-01", "2024-03-31", 9000.0, 8000.0));
        map.put("2024-03", marBills);

        return map;
    }

    /**
     * 创建单个账单
     */
    private BillDocument createBill(String accountNo, String startDate, String endDate,
                                    Double revenue, Double expense) {
        BillDocument bill = new BillDocument();
        bill.setAccountNo(accountNo);
        bill.setStartTime(LocalDateTime.parse(startDate + "T00:00:00"));
        bill.setEndTime(LocalDateTime.parse(endDate + "T23:59:59"));
        bill.setRevenueAmount(revenue);
        bill.setExpenseAmount(expense);
        bill.setBaseResolved(true);
        return bill;
    }

    @Test
    @DisplayName("testGetMonthlyTrend - 测试月度趋势计算")
    void testGetMonthlyTrend() {
        // Given: 模拟 DAO 返回按月份分组的账单数据
        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(billsByMonth);

        // When: 获取月度趋势
        List<MonthlyTrendData> result = service.getMonthlyTrend(null, 3);

        // Then: 验证结果
        assertNotNull(result, "结果不应为空");
        assertEquals(3, result.size(), "应返回3个月的数据");

        // 验证2024-01月数据
        MonthlyTrendData janData = result.get(0);
        assertEquals("2024-01", janData.getMonth());
        assertEquals(12000.0, janData.getIncome(), 0.001, "1月收入应为12000");
        assertEquals(7500.0, janData.getExpense(), 0.001, "1月支出应为7500");
        assertEquals(4500.0, janData.getNetSaving(), 0.001, "1月净储蓄应为4500");
        assertEquals(2, janData.getBillCount(), "1月应有2个账单");

        // 验证2024-02月数据
        MonthlyTrendData febData = result.get(1);
        assertEquals("2024-02", febData.getMonth());
        assertEquals(15000.0, febData.getIncome(), 0.001, "2月收入应为15000");
        assertEquals(9000.0, febData.getExpense(), 0.001, "2月支出应为9000");
        assertEquals(6000.0, febData.getNetSaving(), 0.001, "2月净储蓄应为6000");
        assertEquals(2, febData.getBillCount(), "2月应有2个账单");

        // 验证2024-03月数据
        MonthlyTrendData marData = result.get(2);
        assertEquals("2024-03", marData.getMonth());
        assertEquals(9000.0, marData.getIncome(), 0.001, "3月收入应为9000");
        assertEquals(8000.0, marData.getExpense(), 0.001, "3月支出应为8000");
        assertEquals(1000.0, marData.getNetSaving(), 0.001, "3月净储蓄应为1000");
        assertEquals(1, marData.getBillCount(), "3月应有1个账单");

        // 验证数据按月份排序
        assertTrue(result.get(0).getMonth().compareTo(result.get(1).getMonth()) < 0,
                "数据应按月份升序排列");

        verify(statisticsDao, times(1)).getBillsByMonth(isNull());
    }

    @Test
    @DisplayName("testGetMonthlyTrend_WithAccountFilter - 测试按账号过滤")
    void testGetMonthlyTrend_WithAccountFilter() {
        // Given: 设置账号过滤条件
        String accountNo = "acc001";
        when(statisticsDao.getBillsByMonth(accountNo)).thenReturn(billsByMonth);

        // When: 获取指定账号的月度趋势
        List<MonthlyTrendData> result = service.getMonthlyTrend(accountNo, 3);

        // Then: 验证结果
        assertNotNull(result, "结果不应为空");
        assertEquals(3, result.size(), "应返回3个月的数据");

        // 验证正确传递了账号参数到 DAO
        verify(statisticsDao, times(1)).getBillsByMonth(accountNo);
        verify(statisticsDao, never()).getBillsByMonth(isNull());
    }

    @Test
    @DisplayName("testGetMonthlyTrend_LimitMonths - 测试限制月份数量")
    void testGetMonthlyTrend_LimitMonths() {
        // Given: 模拟返回6个月的数据
        Map<String, List<BillDocument>> sixMonthsData = new LinkedHashMap<>();
        for (int i = 1; i <= 6; i++) {
            String month = String.format("2024-%02d", i);
            List<BillDocument> bills = new ArrayList<>();
            bills.add(createBill("acc001",
                    String.format("2024-%02d-01", i),
                    String.format("2024-%02d-28", i),
                    5000.0, 3000.0));
            sixMonthsData.put(month, bills);
        }
        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(sixMonthsData);

        // When: 只获取最近3个月
        List<MonthlyTrendData> result = service.getMonthlyTrend(null, 3);

        // Then: 验证只返回3个月
        assertNotNull(result, "结果不应为空");
        assertEquals(3, result.size(), "应只返回3个月的数据");
    }

    @Test
    @DisplayName("testGetHealthMetrics - 测试健康度指标计算")
    void testGetHealthMetrics() {
        // Given: 模拟 DAO 返回已解析的账单文档
        when(statisticsDao.getResolvedBillDocuments(isNull())).thenReturn(testBills);

        // 模拟健康分析引擎的行为
        doAnswer(invocation -> {
            HealthMetricsData metrics = invocation.getArgument(0);
            metrics.setHealthScore(75);
            metrics.setHealthStatus(HealthStatus.GOOD);
            metrics.setAlerts(Collections.emptyList());
            return null;
        }).when(healthAnalysisEngine).analyze(any(HealthMetricsData.class));

        // When: 获取健康度指标
        HealthMetricsData result = service.getHealthMetrics(null);

        // Then: 验证计算结果
        assertNotNull(result, "结果不应为空");

        // 总收入 = 10000 + 2000 + 12000 + 3000 + 9000 = 36000
        // 总支出 = 6000 + 1500 + 7000 + 2000 + 8000 = 24500
        // 月份数 = 3
        // 月均收入 = 36000 / 3 = 12000
        // 月均支出 = 24500 / 3 = 8166.67
        // 总净资产 = 36000 - 24500 = 11500
        // 储蓄率 = 11500 / 36000 * 100 = 31.94%
        // 收支比 = 24500 / 36000 = 0.68

        assertEquals(12000.0, result.getAvgMonthlyIncome(), 0.01, "月均收入应为12000");
        assertEquals(8166.67, result.getAvgMonthlyExpense(), 0.01, "月均支出应为8166.67");
        assertEquals(31.94, result.getSavingRate(), 0.01, "储蓄率应为31.94");
        assertEquals(0.68, result.getIncomeExpenseRatio(), 0.01, "收支比应为0.68");
        assertEquals(11500.0, result.getTotalNetSaving(), 0.01, "总净资产应为11500");
        assertEquals(3, result.getMonthsCovered(), "应覆盖3个月");

        // 验证调用了健康分析引擎
        verify(healthAnalysisEngine, times(1)).analyze(any(HealthMetricsData.class));
        verify(statisticsDao, times(1)).getResolvedBillDocuments(isNull());
    }

    @Test
    @DisplayName("testGetVolatilityAnalysis - 测试波动分析计算")
    void testGetVolatilityAnalysis() {
        // Given: 模拟 DAO 返回按月份分组的账单数据
        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(billsByMonth);

        // When: 获取波动分析
        VolatilityAnalysisData result = service.getVolatilityAnalysis(null);

        // Then: 验证计算结果
        assertNotNull(result, "结果不应为空");

        // 月支出: 1月=7500, 2月=9000, 3月=8000
        // 均值 = (7500 + 9000 + 8000) / 3 = 8166.67
        // 方差 = [(7500-8166.67)^2 + (9000-8166.67)^2 + (8000-8166.67)^2] / 3
        //      = [444444.89 + 688888.89 + 27777.89] / 3 = 386037.22
        // 标准差 = sqrt(386037.22) = 621.32
        // 波动率 = 621.32 / 8166.67 = 0.076

        assertEquals(8166.67, result.getMeanExpense(), 0.01, "均值支出应为8166.67");
        assertEquals(621.32, result.getStdDeviation(), 0.01, "标准差应为621.32");
        assertEquals(0.08, result.getVolatilityRate(), 0.01, "波动率应为0.08");
        assertEquals(9000.0, result.getMaxExpense(), 0.001, "最高支出应为9000");
        assertEquals(7500.0, result.getMinExpense(), 0.001, "最低支出应为7500");
        assertEquals(1500.0, result.getExpenseRange(), 0.001, "支出极差应为1500");

        // 验证月度数据
        assertNotNull(result.getMonthlyData(), "月度数据不应为空");
        assertEquals(3, result.getMonthlyData().size(), "应有3个月的波动数据");

        // 验证波动性评价
        assertEquals("消费非常稳定，波动很小", result.getVolatilityAssessment(),
                "波动率<0.1时应评价为'消费非常稳定'");

        verify(statisticsDao, times(1)).getBillsByMonth(isNull());
    }

    @Test
    @DisplayName("testGetOverview - 测试统计总览计算")
    void testGetOverview() {
        // Given: 模拟 DAO 返回已解析的账单文档
        when(statisticsDao.getResolvedBillDocuments(isNull())).thenReturn(testBills);
        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(billsByMonth);

        // 模拟健康分析引擎
        doAnswer(invocation -> {
            HealthMetricsData metrics = invocation.getArgument(0);
            metrics.setHealthScore(75);
            metrics.setHealthStatus(HealthStatus.GOOD);
