        }).when(healthAnalysisEngine).analyze(any(HealthMetricsData.class));

        // When: 获取统计总览
        StatisticsOverview result = service.getOverview(null);

        // Then: 验证总览数据
        assertNotNull(result, "结果不应为空");

        // 验证健康度指标
        assertNotNull(result.getHealth(), "健康度指标不应为空");
        assertEquals(75, result.getHealth().getHealthScore(), "健康得分应为75");

        // 验证趋势数据
        assertNotNull(result.getRecentTrend(), "趋势数据不应为空");
        assertEquals(3, result.getRecentTrend().size(), "应有3个月的趋势数据");

        // 验证日期范围
        assertEquals(LocalDate.of(2024, 1, 1), result.getDataStartDate(),
                "数据起始日期应为2024-01-01");
        assertEquals(LocalDate.of(2024, 3, 31), result.getDataEndDate(),
                "数据结束日期应为2024-03-31");

        // 验证统计信息
        assertEquals(5, result.getTotalBills(), "总账单数应为5");
        assertEquals(3, result.getTotalMonths(), "总月份数应为3");

        // 验证账号列表
        assertNotNull(result.getAccounts(), "账号列表不应为空");
        assertEquals(1, result.getAccounts().size(), "应有1个账号");
        assertEquals("acc001", result.getAccounts().get(0), "账号应为acc001");

        verify(statisticsDao, times(1)).getResolvedBillDocuments(isNull());
    }

    @Test
    @DisplayName("testGetMonthlyTrend_NoData - 测试无数据情况")
    void testGetMonthlyTrend_NoData() {
        // Given: 模拟 DAO 返回空数据
        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(Collections.emptyMap());

