                createBill("acc001", "2024-01-01", "2024-01-31", 5000.0, 3000.0)));
        highVolatilityData.put("2024-02", Collections.singletonList(
                createBill("acc001", "2024-02-01", "2024-02-29", 5000.0, 10000.0)));
        highVolatilityData.put("2024-03", Collections.singletonList(
                createBill("acc001", "2024-03-01", "2024-03-31", 5000.0, 4000.0)));

        when(statisticsDao.getBillsByMonth(isNull())).thenReturn(highVolatilityData);

        // When: 获取波动分析
        VolatilityAnalysisData result = service.getVolatilityAnalysis(null);

        // Then: 验证高波动计算结果
        assertNotNull(result, "结果不应为空");

        // 月支出: 1月=3000, 2月=10000, 3月=4000
        // 均值 = (3000 + 10000 + 4000) / 3 = 5666.67
        // 方差 = [(3000-5666.67)^2 + (10000-5666.67)^2 + (4000-5666.67)^2] / 3
        //      = [7111111.89 + 18777777.89 + 2777777.89] / 3 = 9555555.89
        // 标准差 = sqrt(9555555.89) = 3091.21
        // 波动率 = 3091.21 / 5666.67 = 0.545

        assertEquals(5666.67, result.getMeanExpense(), 0.01, "均值支出应为5666.67");
        assertEquals(3091.21, result.getStdDeviation(), 0.01, "标准差应为3091.21");
        assertEquals(0.55, result.getVolatilityRate(), 0.01, "波动率应为0.55");

        // 验证波动性评价
        assertEquals("消费波动异常，建议审查消费习惯", result.getVolatilityAssessment(),
                "波动率>=0.3时应评价为'消费波动异常'");

        // 验证高消费月份
        assertTrue(result.getHighExpenseMonths().contains("2024-02"),
                "2月应被识别为高消费月份");
    }

