package com.harmony.uspace.service.statistics;

import com.harmony.uspace.dao.StatisticsDao;
import com.harmony.uspace.domain.BillDocument;
import com.harmony.uspace.dto.statistics.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.util.*;
import java.util.stream.Collectors;

/**
 * 账单文档统计服务
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class BillDocumentStatisticsService {

    private final StatisticsDao statisticsDao;
    private final HealthAnalysisEngine healthAnalysisEngine;

    private static final DateTimeFormatter MONTH_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM");

    /**
     * 获取月度收支趋势
     *
     * @param accountNo 账号（可选）
     * @param months 获取最近N个月
     * @return 月度趋势数据列表
     */
    public List<MonthlyTrendData> getMonthlyTrend(String accountNo, int months) {
        log.debug("Getting monthly trend for account: {}, months: {}", accountNo, months);

        Map<String, List<BillDocument>> billsByMonth = statisticsDao.getBillsByMonth(accountNo);

        // 生成最近N个月的月份列表
        List<String> lastNMonths = generateLastNMonths(months);

        // 填充数据，没有数据的月份显示为0
        Map<String, MonthlyTrendData> monthDataMap = new HashMap<>();
        for (Map.Entry<String, List<BillDocument>> entry : billsByMonth.entrySet()) {
            String month = entry.getKey();
            List<BillDocument> bills = entry.getValue();

            double income = bills.stream()
                    .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
                    .sum();

            double expense = bills.stream()
                    .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
                    .sum();

            double netSaving = income - expense;
            int billCount = bills.size();

            monthDataMap.put(month, MonthlyTrendData.builder()
                    .month(month)
                    .income(income)
                    .expense(expense)
                    .netSaving(netSaving)
                    .billCount(billCount)
                    .build());
        }

        // 按月份顺序填充完整的数据
        List<MonthlyTrendData> trendData = lastNMonths.stream()
                .map(month -> monthDataMap.getOrDefault(month, MonthlyTrendData.builder()
                        .month(month)
                        .income(0.0)
                        .expense(0.0)
                        .netSaving(0.0)
                        .billCount(0)
                        .build()))
                .collect(Collectors.toList());

        log.debug("Returning {} months of trend data ({} with data)", trendData.size(),
                trendData.stream().filter(d -> d.getBillCount() > 0).count());
        return trendData;
    }

    /**
     * 生成最近N个月的月份列表（升序）
     * 例如：months=3，当前是2025-03，返回 ["2024-12", "2025-01", "2025-02"]
     */
    private List<String> generateLastNMonths(int months) {
        List<String> result = new ArrayList<>();
        YearMonth current = YearMonth.now();

        for (int i = months - 1; i >= 0; i--) {
            result.add(current.minusMonths(i).format(MONTH_FORMATTER));
        }

        return result;
    }

    /**
     * 获取健康度指标
     *
     * @param accountNo 账号（可选）
     * @return 健康度指标数据
     */
    public HealthMetricsData getHealthMetrics(String accountNo) {
        log.debug("Getting health metrics for account: {}", accountNo);

        List<BillDocument> bills = statisticsDao.getResolvedBillDocuments(accountNo);

        if (bills.isEmpty()) {
            log.warn("No resolved bills found for account: {}", accountNo);
            return HealthMetricsData.builder()
                    .avgMonthlyIncome(0.0)
                    .avgMonthlyExpense(0.0)
                    .savingRate(0.0)
                    .incomeExpenseRatio(0.0)
                    .totalNetSaving(0.0)
                    .monthsCovered(0)
                    .healthScore(0)
                    .alerts(Collections.emptyList())
                    .build();
        }

        // Calculate totals
        double totalIncome = bills.stream()
                .mapToDouble(b -> b.getRevenueAmount() != null ? b.getRevenueAmount() : 0.0)
                .sum();

        double totalExpense = bills.stream()
                .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
                .sum();

        // Get unique months count
        Set<String> uniqueMonths = bills.stream()
                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
                .collect(Collectors.toSet());

        int monthsCount = uniqueMonths.size();

        // Calculate metrics
        double avgMonthlyIncome = monthsCount > 0 ? totalIncome / monthsCount : 0.0;
        double avgMonthlyExpense = monthsCount > 0 ? totalExpense / monthsCount : 0.0;
        double totalNetSaving = totalIncome - totalExpense;
        double savingRate = totalIncome > 0 ? (totalNetSaving / totalIncome) * 100 : 0.0;
        double incomeExpenseRatio = totalIncome > 0 ? totalExpense / totalIncome : 0.0;

        // Round to 2 decimal places
        avgMonthlyIncome = round(avgMonthlyIncome);
        avgMonthlyExpense = round(avgMonthlyExpense);
        totalNetSaving = round(totalNetSaving);
        savingRate = round(savingRate);
        incomeExpenseRatio = round(incomeExpenseRatio);

        HealthMetricsData metrics = HealthMetricsData.builder()
                .avgMonthlyIncome(avgMonthlyIncome)
                .avgMonthlyExpense(avgMonthlyExpense)
                .savingRate(savingRate)
                .incomeExpenseRatio(incomeExpenseRatio)
                .totalNetSaving(totalNetSaving)
                .monthsCovered(monthsCount)
                .build();

        // Run health analysis
        healthAnalysisEngine.analyze(metrics);

        log.debug("Health metrics calculated - Score: {}, Status: {}",
                metrics.getHealthScore(), metrics.getHealthStatus());

        return metrics;
    }

    /**
     * 获取消费波动分析
     *
     * @param accountNo 账号（可选）
     * @return 波动分析数据
     */
    public VolatilityAnalysisData getVolatilityAnalysis(String accountNo) {
        log.debug("Getting volatility analysis for account: {}", accountNo);

        Map<String, List<BillDocument>> billsByMonth = statisticsDao.getBillsByMonth(accountNo);

        if (billsByMonth.isEmpty()) {
            log.warn("No bills found for volatility analysis for account: {}", accountNo);
            return VolatilityAnalysisData.builder()
                    .meanExpense(0.0)
                    .stdDeviation(0.0)
                    .volatilityRate(0.0)
                    .maxExpense(0.0)
                    .minExpense(0.0)
                    .expenseRange(0.0)
                    .monthlyData(Collections.emptyList())
                    .highExpenseMonths(Collections.emptyList())
                    .lowExpenseMonths(Collections.emptyList())
                    .volatilityAssessment("暂无数据")
                    .build();
        }

        // Calculate monthly expenses
        List<MonthlyExpenseData> monthlyExpenses = billsByMonth.entrySet().stream()
                .map(entry -> {
                    String month = entry.getKey();
                    double expense = entry.getValue().stream()
                            .mapToDouble(b -> b.getExpenseAmount() != null ? b.getExpenseAmount() : 0.0)
                            .sum();
                    return new MonthlyExpenseData(month, expense);
                })
                .sorted(Comparator.comparing(MonthlyExpenseData::getMonth))
                .collect(Collectors.toList());

        // Calculate statistics
        double meanExpense = monthlyExpenses.stream()
                .mapToDouble(MonthlyExpenseData::getExpense)
                .average()
                .orElse(0.0);

        double variance = monthlyExpenses.stream()
                .mapToDouble(data -> Math.pow(data.getExpense() - meanExpense, 2))
                .average()
                .orElse(0.0);

        double stdDeviation = Math.sqrt(variance);

        double maxExpense = monthlyExpenses.stream()
                .mapToDouble(MonthlyExpenseData::getExpense)
                .max()
                .orElse(0.0);

        double minExpense = monthlyExpenses.stream()
                .mapToDouble(MonthlyExpenseData::getExpense)
                .min()
                .orElse(0.0);

        double volatilityRate = meanExpense > 0 ? stdDeviation / meanExpense : 0.0;

        // Build monthly volatility data
        List<MonthlyVolatility> monthlyData = monthlyExpenses.stream()
                .map(data -> {
                    double deviationFromMean = data.getExpense() - meanExpense;
                    double deviationPercent = meanExpense > 0 ? (deviationFromMean / meanExpense) * 100 : 0.0;
                    VolatilityLevel level = determineVolatilityLevel(deviationFromMean, stdDeviation);

                    return MonthlyVolatility.builder()
                            .month(data.getMonth())
                            .expense(data.getExpense())
                            .deviationFromMean(round(deviationFromMean))
                            .deviationPercent(round(deviationPercent))
                            .level(level)
                            .build();
                })
                .collect(Collectors.toList());

        // Identify high and low expense months
        double upperThreshold = meanExpense + stdDeviation;
        double lowerThreshold = meanExpense - stdDeviation;

        List<String> highExpenseMonths = monthlyExpenses.stream()
                .filter(data -> data.getExpense() > upperThreshold)
                .map(MonthlyExpenseData::getMonth)
                .collect(Collectors.toList());

        List<String> lowExpenseMonths = monthlyExpenses.stream()
                .filter(data -> data.getExpense() < lowerThreshold)
                .map(MonthlyExpenseData::getMonth)
                .collect(Collectors.toList());

        // Generate volatility assessment
        String volatilityAssessment = generateVolatilityAssessment(volatilityRate);

        return VolatilityAnalysisData.builder()
                .meanExpense(round(meanExpense))
                .stdDeviation(round(stdDeviation))
                .volatilityRate(round(volatilityRate))
                .maxExpense(round(maxExpense))
                .minExpense(round(minExpense))
                .expenseRange(round(maxExpense - minExpense))
                .monthlyData(monthlyData)
                .highExpenseMonths(highExpenseMonths)
                .lowExpenseMonths(lowExpenseMonths)
                .volatilityAssessment(volatilityAssessment)
                .build();
    }

    /**
     * 获取统计总览
     *
     * @param accountNo 账号（可选）
     * @return 统计总览数据
     */
    public StatisticsOverview getOverview(String accountNo) {
        log.debug("Getting statistics overview for account: {}", accountNo);

        List<BillDocument> bills = statisticsDao.getResolvedBillDocuments(accountNo);

        if (bills.isEmpty()) {
            log.warn("No bills found for overview for account: {}", accountNo);
            return StatisticsOverview.builder()
                    .health(HealthMetricsData.builder().build())
                    .recentTrend(Collections.emptyList())
                    .totalBills(0)
                    .totalMonths(0)
                    .accounts(Collections.emptyList())
                    .build();
        }

        // Get health metrics
        HealthMetricsData health = getHealthMetrics(accountNo);

        // Get recent 6 months trend
        List<MonthlyTrendData> recentTrend = getMonthlyTrend(accountNo, 6);

        // Calculate date range
        LocalDate startDate = bills.stream()
                .map(BillDocument::getStartTime)
                .filter(Objects::nonNull)
                .map(LocalDateTime::toLocalDate)
                .min(LocalDate::compareTo)
                .orElse(null);

        LocalDate endDate = bills.stream()
                .map(BillDocument::getEndTime)
                .filter(Objects::nonNull)
                .map(LocalDateTime::toLocalDate)
                .max(LocalDate::compareTo)
                .orElse(null);

        // Get unique accounts
        List<String> accounts = bills.stream()
                .map(BillDocument::getAccountNo)
                .filter(Objects::nonNull)
                .distinct()
                .collect(Collectors.toList());

        // Get unique months count
        int totalMonths = (int) bills.stream()
                .map(b -> b.getStartTime() != null ? b.getStartTime().format(MONTH_FORMATTER) : "unknown")
                .distinct()
                .count();

        return StatisticsOverview.builder()
                .health(health)
                .recentTrend(recentTrend)
                .dataStartDate(startDate)
                .dataEndDate(endDate)
                .totalBills(bills.size())
                .totalMonths(totalMonths)
                .accounts(accounts)
                .build();
    }

    /**
     * 确定波动级别
     */
    private VolatilityLevel determineVolatilityLevel(double deviation, double stdDev) {
        double absDeviation = Math.abs(deviation);
        if (absDeviation > 2 * stdDev) {
            return VolatilityLevel.EXTREME;
        } else if (absDeviation > stdDev) {
            return VolatilityLevel.HIGH;
        } else {
            return VolatilityLevel.LOW;
        }
    }

    /**
     * 生成波动性评价
     */
    private String generateVolatilityAssessment(double volatilityRate) {
        if (volatilityRate < 0.1) {
            return "消费非常稳定，波动很小";
        } else if (volatilityRate < 0.2) {
            return "消费较为稳定，波动在正常范围内";
        } else if (volatilityRate < 0.3) {
            return "消费波动偏高，建议关注异常支出";
        } else {
            return "消费波动异常，建议审查消费习惯";
        }
    }

    /**
     * 四舍五入到2位小数
     */
    private double round(double value) {
        return BigDecimal.valueOf(value)
                .setScale(2, RoundingMode.HALF_UP)
                .doubleValue();
    }

    /**
     * 内部类：月度支出数据
     */
    private static class MonthlyExpenseData {
        private final String month;
        private final double expense;

        public MonthlyExpenseData(String month, double expense) {
            this.month = month;
            this.expense = expense;
        }

        public String getMonth() {
            return month;
        }

        public double getExpense() {
            return expense;
        }
    }
}

