package com.harmony.uspace.service;

import com.harmony.uspace.dao.BillDocumentDao;
import com.harmony.uspace.dao.BillRowDao;
import com.harmony.uspace.domain.BillDocument;
import com.harmony.uspace.domain.BillRow;
import com.harmony.uspace.options.ResolveStatus;
import com.harmony.uspace.repository.BillDocumentRepository;
import com.harmony.uspace.repository.BillRowRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * @author wuxin
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class BillRowService {

    private final BillDocumentRepository billDocumentRepository;
    private final BillRowRepository billRowRepository;

    private final BillRowDao billRowDao;
    private final BillDocumentDao billDocumentDao;

    public void handleBillRowsAsync(String billDocumentRecordId, List<BillRow> billRows) {
        BillDocument billDocument = billDocumentRepository.getOneById(billDocumentRecordId);
        ResolveStatus rowResolveStatus = billDocument.getRowResolveStatus();
        if (!ResolveStatus.isProcessable(rowResolveStatus)) {
            log.error("Unsupported status {}", rowResolveStatus);
            return;
        }

        billDocumentDao.updateRowResolveStatus(billDocumentRecordId, ResolveStatus.PROCESSING);

        Exception error = null;
        for (BillRow billRow : billRows) {
            try {
                saveBillRowIfAbsent(billRow);
            } catch (Exception e) {
                log.warn("BillRow save failed, {}", billRow, e);
                error = e;
            }
        }
        ResolveStatus resolveStatus = (error == null) ? ResolveStatus.SUCCESS : ResolveStatus.FAILURE;
        billDocumentDao.updateRowResolveStatus(billDocumentRecordId, resolveStatus);
    }

    private void saveBillRowIfAbsent(BillRow billRow) {
        String transactionOrderNumber = billRow.getTransactionOrderNumber();
        if (billRowDao.existsByTransactionOrderNumber(transactionOrderNumber)) {
            log.warn("BillRow already exists: transactionOrderNumber={}", transactionOrderNumber);
            return;
        }
        billRowRepository.save(billRow);
    }

}

