package com.harmony.uspace.dao

import com.harmony.bitable.oapi.cursor.toElementList
import com.harmony.uspace.domain.BillDocument
import com.harmony.uspace.repository.BillDocumentRepository
import org.springframework.stereotype.Component
import java.time.format.DateTimeFormatter

/**
 * 统计数据访问层
 */
@Component
class StatisticsDao(private val billDocumentRepository: BillDocumentRepository) {

    private val monthFormatter = DateTimeFormatter.ofPattern("yyyy-MM")

    /**
     * 获取所有已基础解析完成的账单文档
     */
    fun getResolvedBillDocuments(accountNo: String? = null): List<BillDocument> {
        return if (accountNo.isNullOrBlank()) {
            billDocumentRepository.search {
                where {
                    BillDocument::getBaseResolved `is` true
                }
            }.toElementList()
        } else {
            billDocumentRepository.search {
                where {
                    BillDocument::getBaseResolved `is` true
                    BillDocument::getAccountNo `is` accountNo
                }
            }.toElementList()
        }
    }

    /**
     * 按月份分组统计账单
     */
    fun getBillsByMonth(accountNo: String? = null): Map<String, List<BillDocument>> {
        return getResolvedBillDocuments(accountNo)
            .groupBy { bill ->
                bill.startTime?.format(monthFormatter) ?: "unknown"
            }
    }
}

