import org.springframework.stereotype.Component
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.YearMonth

@Component
class BillRowDao(private val billRowRepository: BillRowRepository) {

    fun existsByMerchantOrderNumber(merchantOrderNumber: String): Boolean {
        return billRowRepository.count {
            BillRow::getMerchantOrderNumber `is` merchantOrderNumber
        } > 0
    }

    fun existsByTransactionOrderNumber(transactionOrderNumber: String): Boolean {
        return billRowRepository.count {
            BillRow::getTransactionOrderNumber `is` transactionOrderNumber
        } > 0
    }

    /**
     * 按月份查询交易明细
     * @param month 月份格式：yyyy-MM
     * @param category 交易分类（可选）
     * @param flowType 收支类型（可选，如"收入"/"支出"）
     * @param pageSize 页大小
     * @param pageToken 分页令牌
     * @return 交易明细列表和下一页令牌
     */
    fun getTransactionsByMonth(
        month: String,
        category: String? = null,
        flowType: String? = null,
        pageSize: Int = 100,
        pageToken: String? = null
    ): Pair<List<BillRow>, String?> {
        val yearMonth = YearMonth.parse(month, java.time.format.DateTimeFormatter.ofPattern("yyyy-MM"))
        val startOfMonth = yearMonth.atDay(1).atStartOfDay()
        val endOfMonth = yearMonth.plusMonths(1).atDay(1).atStartOfDay()

        val result = billRowRepository.search {
            where {
