package com.harmony.uspace.controller;

import com.harmony.uspace.dto.statistics.*;
import com.harmony.uspace.service.statistics.BillDocumentStatisticsService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

/**
 * 统计分析 API 控制器
 */
@RestController
@RequestMapping("/api/statistics")
@RequiredArgsConstructor
public class StatisticsController {

    private final BillDocumentStatisticsService statisticsService;

    /**
     * 获取统计总览（仪表盘首页）
     *
     * @param accountNo 账号（可选）
     * @return 统计总览数据
     */
    @GetMapping("/overview")
    public ResponseEntity<StatisticsOverview> getOverview(
            @RequestParam(required = false) String accountNo) {
        StatisticsOverview overview = statisticsService.getOverview(accountNo);
        return ResponseEntity.ok(overview);
    }

    /**
     * 获取月度收支趋势
     *
     * @param accountNo 账号（可选）
     * @param startMonth 开始月份（格式：yyyy-MM），可选
     * @param endMonth 结束月份（格式：yyyy-MM），可选
     * @param months 获取最近N个月（当未指定月份范围时使用，默认12）
     * @return 月度趋势数据列表
     */
    @GetMapping("/monthly-trend")
    public ResponseEntity<List<MonthlyTrendData>> getMonthlyTrend(
            @RequestParam(required = false) String accountNo,
            @RequestParam(required = false) String startMonth,
            @RequestParam(required = false) String endMonth,
            @RequestParam(required = false) Integer months) {
        // 如果没有指定 months，默认为 12
        if (months == null || months <= 0) {
            months = 12;
        }
        List<MonthlyTrendData> trend = statisticsService.getMonthlyTrend(accountNo, startMonth, endMonth, months);
        return ResponseEntity.ok(trend);
    }

    /**
     * 获取健康度指标
     *
     * @param accountNo 账号（可选）
     * @return 健康度指标数据
     */
    @GetMapping("/health")
    public ResponseEntity<HealthMetricsData> getHealthMetrics(
            @RequestParam(required = false) String accountNo) {
        HealthMetricsData health = statisticsService.getHealthMetrics(accountNo);
        return ResponseEntity.ok(health);
    }

    /**
     * 获取消费波动分析
     *
     * @param accountNo 账号（可选）
     * @return 波动分析数据
     */
    @GetMapping("/volatility")
    public ResponseEntity<VolatilityAnalysisData> getVolatilityAnalysis(
            @RequestParam(required = false) String accountNo) {
        VolatilityAnalysisData volatility = statisticsService.getVolatilityAnalysis(accountNo);
        return ResponseEntity.ok(volatility);
    }
}

