   335→            return value != null && !isNaN(value) ? value : defaultValue;
   336→        }
   337→
   338→        // 工具函数：安全格式化金额
   339→        function formatMoney(value) {
   340→            const num = safeValue(value, 0);
   341→            return '¥' + num.toFixed(2);
   342→        }
   343→
   344→        // 工具函数：安全获取对象属性
   345→        function safeGet(obj, key, defaultValue = null) {
   346→            return obj && obj[key] != null ? obj[key] : defaultValue;
   347→        }
   348→
   349→        // 切换时间范围类型
   350→        function toggleTimeRangeFilter() {
   351→            const rangeType = document.getElementById('timeRangeType').value;
   352→            const monthsContainer = document.getElementById('monthsFilterContainer');
   353→            const customContainer = document.getElementById('customRangeContainer');
   354→
   355→            if (rangeType === 'custom') {
   356→                monthsContainer.style.display = 'none';
   357→                customContainer.style.display = 'inline';
   358→            } else {
   359→                monthsContainer.style.display = 'inline';
   360→                customContainer.style.display = 'none';
   361→            }
   362→        }
