   364→        // 加载数据
   365→        async function loadData() {
   366→            const accountNo = document.getElementById('accountFilter').value;
   367→            const rangeType = document.getElementById('timeRangeType').value;
   368→
   369→            // 构建请求 URL
   370→            let trendUrl = `${API_BASE}/monthly-trend?accountNo=${accountNo}`;
   371→
   372→            if (rangeType === 'custom') {
   373→                const startMonth = document.getElementById('startMonth').value;
   374→                const endMonth = document.getElementById('endMonth').value;
   375→                if (startMonth) trendUrl += `&startMonth=${startMonth}`;
   376→                if (endMonth) trendUrl += `&endMonth=${endMonth}`;
   377→            } else {
   378→                const months = document.getElementById('monthsFilter').value;
   379→                trendUrl += `&months=${months}`;
   380→            }
   381→
   382→            document.getElementById('loading').style.display = 'block';
   383→            document.getElementById('content').style.display = 'none';
   384→
   385→            try {
   386→                const [overview, trend, health, volatility] = await Promise.all([
   387→                    fetch(`${API_BASE}/overview?accountNo=${accountNo}`).then(r => r.json()),
   388→                    fetch(trendUrl).then(r => r.json()),
   389→                    fetch(`${API_BASE}/health?accountNo=${accountNo}`).then(r => r.json()),
   390→                    fetch(`${API_BASE}/volatility?accountNo=${accountNo}`).then(r => r.json())
   391→                ]);
   392→
   393→                // 更新账号列表
   394→                if (overview.accounts && overview.accounts.length > 0) {
   395→                    updateAccountFilter(overview.accounts);
   396→                }
   397→
   398→                renderHealthStatus(health);
