   401→                renderTrendChart(trend, health);
   402→                renderVolatilityChart(volatility);
   403→                renderVolatilityStats(volatility);
   404→                renderOverview(overview);
   405→
   406→                document.getElementById('loading').style.display = 'none';
   407→                document.getElementById('content').style.display = 'grid';
   408→            } catch (error) {
