package com.harmony.uspace.service.statistics;

import com.harmony.uspace.dao.BillRowDao;
import com.harmony.uspace.domain.BillRow;
import com.harmony.uspace.dto.statistics.*;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.time.format.DateTimeFormatter;
import java.util.*;
import java.util.stream.Collectors;

/**
 * 交易明细查询服务
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class TransactionDetailsService {

    private final BillRowDao billRowDao;

    private static final DateTimeFormatter MONTH_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM");
    private static final DateTimeFormatter DATETIME_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    /**
     * 获取指定月份的交易明细（带分页和分类汇总）
     *
     * @param month 月份（格式：yyyy-MM）
     * @param category 交易分类（可选）
     * @param flowType 收支类型（可选）
     * @param page 页码（从0开始）
     * @param size 每页大小
     * @return 交易明细响应
     */
    public TransactionDetailResponse getTransactionDetails(
            String month,
            String category,
            String flowType,
            int page,
            int size) {

        log.debug("Getting transactions for month: {}, category: {}, flowType: {}, page: {}, size: {}",
                month, category, flowType, page, size);

        // 计算分页偏移
        int offset = page * size;
        String pageToken = null;

        // 手动实现分页（因为 Bitable DSL 的分页是基于 pageToken 的）
        // 对于大数据量，这里可以优化为使用 cursor 分页
        List<BillRow> allTransactions = billRowDao.getAllTransactionsByMonth(month, category, flowType);

        int totalCount = allTransactions.size();
        int totalPages = (int) Math.ceil((double) totalCount / size);

        // 分页截取
        int fromIndex = Math.min(offset, totalCount);
        int toIndex = Math.min(offset + size, totalCount);
        List<BillRow> pagedTransactions = allTransactions.subList(fromIndex, toIndex);

        // 转换为 DTO
        List<TransactionDetailDTO> transactions = pagedTransactions.stream()
                .map(this::convertToDTO)
                .collect(Collectors.toList());

        // 计算分类汇总
        List<CategorySummaryDTO> categorySummary = calculateCategorySummary(allTransactions);

        return TransactionDetailResponse.builder()
                .transactions(transactions)
                .categorySummary(categorySummary)
                .totalCount(totalCount)
                .currentPage(page)
                .pageSize(size)
                .totalPages(totalPages)
                .month(month)
                .build();
    }

    /**
     * 计算分类汇总
     */
    private List<CategorySummaryDTO> calculateCategorySummary(List<BillRow> transactions) {
        if (transactions.isEmpty()) {
            return Collections.emptyList();
        }

        // 按分类和收支类型分组
        Map<String, List<BillRow>> groupedByCategoryAndFlow = transactions.stream()
                .collect(Collectors.groupingBy(b ->
                        (b.getFlowType() != null ? b.getFlowType() : "未知") + "|" +
                        (b.getTransactionCategory() != null ? b.getTransactionCategory() : "未分类")
                ));

        // 计算各分组的总额和笔数
        List<CategorySummaryDTO> summary = groupedByCategoryAndFlow.entrySet().stream()
                .map(entry -> {
                    String[] parts = entry.getKey().split("\\|");
                    String flowType = parts[0];
                    String category = parts[1];

                    List<BillRow> rows = entry.getValue();
                    double totalAmount = rows.stream()
                            .mapToDouble(b -> b.getAmount() != null ? b.getAmount() : 0.0)
                            .sum();
                    int count = rows.size();

                    return CategorySummaryDTO.builder()
                            .category(category)
                            .flowType(flowType)
                            .totalAmount(round(totalAmount))
                            .transactionCount(count)
                            .percentage(0.0) // 稍后计算
                            .build();
                })
                .sorted((a, b) -> Double.compare(b.getTotalAmount(), a.getTotalAmount()))
                .collect(Collectors.toList());

        // 计算占比（按收支类型分别计算）
        Map<String, Double> flowTypeTotals = summary.stream()
                .collect(Collectors.groupingBy(
                        CategorySummaryDTO::getFlowType,
                        Collectors.summingDouble(CategorySummaryDTO::getTotalAmount)
                ));

        summary = summary.stream()
                .map(s -> {
                    double totalForFlowType = flowTypeTotals.getOrDefault(s.getFlowType(), 0.0);
                    double percentage = totalForFlowType > 0 ? (s.getTotalAmount() / totalForFlowType) * 100 : 0.0;
                    s.setPercentage(round(percentage));
                    return s;
                })
                .collect(Collectors.toList());

        return summary;
    }

    /**
     * 转换 BillRow 为 TransactionDetailDTO
     */
    private TransactionDetailDTO convertToDTO(BillRow billRow) {
        String month = billRow.getTransactionTime() != null
                ? billRow.getTransactionTime().format(MONTH_FORMATTER)
                : null;

        return TransactionDetailDTO.builder()
                .recordId(billRow.getRecordId())
                .transactionTime(billRow.getTransactionTime())
                .transactionCategory(billRow.getTransactionCategory())
                .flowType(billRow.getFlowType())
                .amount(billRow.getAmount())
                .description(billRow.getDescription())
                .paymentMethod(billRow.getPaymentMethod())
                .counterpartyName(billRow.getCounterpartyName())
                .counterpartyAccount(billRow.getCounterpartyAccount())
                .transactionOrderNumber(billRow.getTransactionOrderNumber())
                .remark(billRow.getRemark())
                .month(month)
                .build();
    }

    /**
     * 四舍五入到2位小数
     */
    private double round(double value) {
        return Math.round(value * 100.0) / 100.0;
    }

    /**
     * 获取所有可用的交易分类
     */
    public List<String> getAvailableCategories(String month) {
        List<BillRow> transactions = billRowDao.getAllTransactionsByMonth(month);
        return transactions.stream()
                .map(BillRow::getTransactionCategory)
                .filter(Objects::nonNull)
                .distinct()
                .sorted()
                .collect(Collectors.toList());
    }
}

